import { Transaction, User } from '../types';

// NOTE: Replace this with your actual Google Apps Script Web App URL after deployment
const API_URL = process.env.VITE_GOOGLE_SHEETS_API || '';

// Mocking storage for the demo if API_URL is not set
const getMockData = (): Transaction[] => {
  const data = localStorage.getItem('mock_transactions');
  return data ? JSON.parse(data) : [];
};

const saveMockData = (data: Transaction[]) => {
  localStorage.setItem('mock_transactions', JSON.stringify(data));
};

export const googleSheetsService = {
  async login(email: string, password: string): Promise<User | null> {
    // In a real app, this would hit the API
    // For this prototype, we simulate a login
    if (email && password.length >= 4) {
      return { id: btoa(email), email, name: email.split('@')[0] };
    }
    return null;
  },

  async register(name: string, email: string, password: string): Promise<User | null> {
    return { id: btoa(email), email, name };
  },

  async fetchTransactions(email: string): Promise<Transaction[]> {
    if (!API_URL) {
      return getMockData().filter(t => t.email === email);
    }

    try {
      const response = await fetch(`${API_URL}?action=read&email=${email}`);
      const data = await response.json();
      return data.records || [];
    } catch (error) {
      console.error("Failed to fetch transactions", error);
      return [];
    }
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    if (!API_URL) {
      const data = getMockData();
      data.push({ ...transaction, id: Date.now().toString() });
      saveMockData(data);
      return true;
    }

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'create', ...transaction }),
      });
      return response.ok;
    } catch (error) {
      console.error("Failed to add transaction", error);
      return false;
    }
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    if (!API_URL) {
      const data = getMockData();
      const index = data.findIndex(t => t.id === id);
      if (index !== -1) {
        data[index] = { ...transaction, id };
        saveMockData(data);
        return true;
      }
      return false;
    }

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'update', id, ...transaction }),
      });
      return response.ok;
    } catch (error) {
      console.error("Failed to update transaction", error);
      return false;
    }
  },

  async deleteTransaction(id: string): Promise<boolean> {
    if (!API_URL) {
      const data = getMockData();
      const filtered = data.filter(t => t.id !== id);
      saveMockData(filtered);
      return true;
    }

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'delete', id }),
      });
      return response.ok;
    } catch (error) {
      console.error("Failed to delete transaction", error);
      return false;
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, Transaction, Language } from './types';
import { translations } from './translations';
import { googleSheetsService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import AuthForm from './components/AuthForm';
import { LogOut, Globe, Wallet, Plus, LayoutDashboard, History, BarChart3 } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [lang, setLang] = useState<Language>('en');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'charts'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  const t = translations[lang];

  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);
      loadData(parsedUser.email);
    }
    const savedLang = localStorage.getItem('lang');
    if (savedLang) setLang(savedLang as Language);
  }, []);

  const loadData = async (email: string) => {
    setIsLoading(true);
    const data = await googleSheetsService.fetchTransactions(email);
    setTransactions(data);
    setIsLoading(false);
  };

  const handleLogin = (u: User) => {
    setUser(u);
    localStorage.setItem('user', JSON.stringify(u));
    loadData(u.email);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('user');
    setTransactions([]);
  };

  const toggleLanguage = () => {
    const newLang = lang === 'en' ? 'si' : 'en';
    setLang(newLang);
    localStorage.setItem('lang', newLang);
  };

  const onAddTransaction = async (data: Transaction) => {
    const success = await googleSheetsService.addTransaction(data);
    if (success && user) {
      loadData(user.email);
    }
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-indigo-50 to-blue-100">
        <div className="w-full max-w-md">
          <div className="text-center mb-8">
            <div className="inline-flex items-center justify-center p-3 bg-white rounded-2xl shadow-sm mb-4">
              <Wallet className="w-10 h-10 text-indigo-600" />
            </div>
            <h1 className="text-3xl font-bold text-slate-900 mb-2">{t.title}</h1>
            <p className="text-slate-500">Securely manage your daily finances</p>
          </div>

          <AuthForm t={t} onAuthSuccess={handleLogin} />

          <button 
            onClick={toggleLanguage}
            className="mt-6 flex items-center justify-center gap-2 w-full text-slate-600 hover:text-indigo-600 font-medium transition-colors"
          >
            <Globe className="w-4 h-4" />
            {t.language}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0">
      {/* Sidebar / Desktop Nav */}
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white border-r border-slate-200 p-6 z-20">
        <div className="flex items-center gap-3 mb-10">
          <Wallet className="w-8 h-8 text-indigo-600" />
          <h1 className="font-bold text-lg text-slate-800 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'dashboard' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            {t.dashboard}
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'history' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <History className="w-5 h-5" />
            {t.history}
          </button>
          <button 
            onClick={() => setActiveTab('charts')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'charts' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <BarChart3 className="w-5 h-5" />
            {t.charts}
          </button>
        </div>

        <div className="mt-auto pt-6 border-t border-slate-100 space-y-4">
          <div className="px-4 py-2 bg-slate-50 rounded-lg">
            <p className="text-xs text-slate-400 mb-1">{t.welcome}</p>
            <p className="font-semibold text-slate-700 truncate">{user.name}</p>
          </div>
          <button 
