export default App;

import React, { useState } from 'react';
import { User } from '../types';
import { googleSheetsService } from '../services/googleSheets';

interface AuthFormProps {
  t: any;
  onAuthSuccess: (user: User) => void;
}

const AuthForm: React.FC<AuthFormProps> = ({ t, onAuthSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      if (isLogin) {
        const user = await googleSheetsService.login(email, password);
        if (user) onAuthSuccess(user);
        else setError('Invalid credentials');
      } else {
        const user = await googleSheetsService.register(name, email, password);
        if (user) onAuthSuccess(user);
        else setError('Registration failed');
      }
    } catch (err) {
      setError('Something went wrong. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100">
      <form onSubmit={handleSubmit} className="space-y-4">
        {!isLogin && (
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-1">{t.name}</label>
            <input
              type="text"
              required
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>
        )}
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.email}</label>
          <input
            type="email"
            required
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.password}</label>
          <input
            type="password"
            required
            minLength={4}
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
        </div>

        {error && <p className="text-rose-500 text-sm font-medium">{error}</p>}

        <button
          type="submit"
          disabled={loading}
          className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-[0.98] transition-all disabled:opacity-50"
        >
          {loading ? '...' : isLogin ? t.login : t.register}
        </button>
      </form>

      <div className="mt-6 text-center">
        <button
          onClick={() => setIsLogin(!isLogin)}
          className="text-sm font-semibold text-indigo-600 hover:underline"
        >
          {isLogin ? "Don't have an account? Register" : "Already have an account? Login"}
        </button>
      </div>
    </div>
  );
};

export default AuthForm;

import React, { useState } from 'react';
import { Transaction, User, MonthlySummary, CategoryData } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import { Plus, X } from 'lucide-react';

interface DashboardProps {
  activeTab: 'dashboard' | 'history' | 'charts';
  t: any;
  user: User;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  t, 
  user, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  isLoading 
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  // Group transactions by month for summary
  const monthlySummary: MonthlySummary[] = React.useMemo(() => {
    const summaryMap: Record<string, MonthlySummary> = {};

    transactions.forEach((tx) => {
      const monthKey = tx.month;
      if (!summaryMap[monthKey]) {
        summaryMap[monthKey] = {
          month: monthKey,
          totalGroceries: 0,
          totalVegetables: 0,
          totalFishAndEgg: 0,
          totalChicken: 0,
          totalHouseRent: 0,
          totalBikeExpenses: 0,
          totalPetrol: 0,
          totalExpenses: 0,
          totalCashGiven: 0,
          openingBalance: tx.openingBalance, // Approximation: use first entry's opening balance
          closingBalance: 0
        };
      }
      summaryMap[monthKey].totalGroceries += tx.groceries;
      summaryMap[monthKey].totalVegetables += tx.vegetables;
      summaryMap[monthKey].totalFishAndEgg += tx.fishAndEgg;
      summaryMap[monthKey].totalChicken += tx.chicken;
      summaryMap[monthKey].totalHouseRent += tx.houseRent;
      summaryMap[monthKey].totalBikeExpenses += tx.bikeExpenses;
      summaryMap[monthKey].totalPetrol += tx.petrol;
      summaryMap[monthKey].totalExpenses += tx.totalExpenses;
      summaryMap[monthKey].totalCashGiven += tx.dailyCashGiven;
      // Closing balance is the balance of the last entry in that month (sorted by date)
      summaryMap[monthKey].closingBalance = tx.netBalance; 
    });

    return Object.values(summaryMap).sort((a, b) => b.month.localeCompare(a.month));
  }, [transactions]);

  const latestStats = React.useMemo(() => {
    const totalSpent = transactions.reduce((sum, tx) => sum + tx.totalExpenses, 0);
    const totalReceived = transactions.reduce((sum, tx) => sum + tx.dailyCashGiven, 0);
    const lastBalance = transactions.length > 0 ? transactions[transactions.length - 1].netBalance : 0;

    return { totalSpent, totalReceived, lastBalance };
  }, [transactions]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleCloseForm = () => {
    setShowAddForm(false);
    setEditingTransaction(null);
  };

  return (
    <div className="space-y-6">
      {/* Tab Specific Rendering */}
      {activeTab === 'dashboard' && (
        <>
          <StatsOverview t={t} stats={latestStats} />

          <div className="flex items-center justify-between mt-8">
            <h2 className="text-xl font-bold text-slate-800">{t.addRecord}</h2>
            <button 
              onClick={() => setShowAddForm(true)}
              className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold flex items-center gap-2 shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
            >
              <Plus className="w-5 h-5" />
              {t.addRecord}
            </button>
          </div>

          <div className="grid grid-cols-1 gap-6">
             <h2 className="text-xl font-bold text-slate-800 mt-4">{t.summary}</h2>
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {monthlySummary.map((sum) => (
                  <div key={sum.month} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                    <div className="flex justify-between items-center mb-4">
                       <h3 className="font-bold text-lg text-indigo-600">{sum.month}</h3>
                       <span className="bg-indigo-50 text-indigo-700 text-xs font-bold px-2 py-1 rounded-full">{t.summary}</span>
                    </div>
                    <div className="space-y-2">
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.totalExpenses}</span>
                         <span className="font-semibold text-rose-500">LKR {sum.totalExpenses.toLocaleString()}</span>
                       </div>
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.dailyCashGiven}</span>
                         <span className="font-semibold text-emerald-600">LKR {sum.totalCashGiven.toLocaleString()}</span>
                       </div>
                       <div className="pt-2 border-t border-slate-50 flex justify-between">
                         <span className="font-bold text-slate-700">{t.netBalance}</span>
                         <span className="font-bold text-slate-900">LKR {sum.closingBalance.toLocaleString()}</span>
                       </div>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        </>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800">{t.history}</h2>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions} 
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
          />
        </div>
      )}

      {activeTab === 'charts' && (
        <MonthlyCharts t={t} transactions={transactions} />
      )}

      {/* Form Overlay */}
      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={handleCloseForm}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                email={user.email} 
                initialData={editingTransaction}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  handleCloseForm();
                }} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';

interface TransactionFormProps {
  t: any;
  email: string;
  initialData?: Transaction | null;
  onSubmit: (data: Transaction) => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, email, initialData, onSubmit }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: 0,
    vegetables: 0,
    fishAndEgg: 0,
    chicken: 0,
    houseRent: 0,
    bikeExpenses: 0,
    petrol: 0,
    dailyCashGiven: 0,
    openingBalance: 0,
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries,
        vegetables: initialData.vegetables,
        fishAndEgg: initialData.fishAndEgg,
        chicken: initialData.chicken,
        houseRent: initialData.houseRent,
        bikeExpenses: initialData.bikeExpenses,
        petrol: initialData.petrol,
        dailyCashGiven: initialData.dailyCashGiven,
        openingBalance: initialData.openingBalance,
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? parseFloat(value) || 0 : value
    }));
  };

  const totalExpenses = 
    formData.groceries + 
    formData.vegetables + 
    formData.fishAndEgg + 
    formData.chicken + 
    formData.houseRent + 
    formData.bikeExpenses + 
    formData.petrol;

  const netBalance = formData.openingBalance + formData.dailyCashGiven - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('default', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      email,
      month: monthName,
      totalExpenses,
      netBalance,
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.date}</label>
          <input
            type="date"
            name="date"
            required
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500"
            value={formData.date}
            onChange={handleChange}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.openingBalance}</label>
          <input
            type="number"
            name="openingBalance"
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200"
            value={formData.openingBalance}
            onChange={handleChange}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {[
          { name: 'groceries', label: t.groceries },
          { name: 'vegetables', label: t.vegetables },
          { name: 'fishAndEgg', label: t.fishAndEgg },
          { name: 'chicken', label: t.chicken },
          { name: 'houseRent', label: t.houseRent },
          { name: 'bikeExpenses', label: t.bikeExpenses },
          { name: 'petrol', label: t.petrol },
        ].map(field => (
          <div key={field.name}>
            <label className="block text-sm font-semibold text-slate-700 mb-1">{field.label}</label>
            <input
              type="number"
              name={field.name}
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200"
              value={(formData as any)[field.name]}
              onChange={handleChange}
            />
          </div>
        ))}
        <div>
          <label className="block text-sm font-semibold text-indigo-700 mb-1">{t.dailyCashGiven}</label>
          <input
            type="number"
            name="dailyCashGiven"
            className="w-full px-4 py-2.5 rounded-xl border border-indigo-200 bg-indigo-50 font-bold"
            value={formData.dailyCashGiven}
            onChange={handleChange}
          />
