      <div className="p-6 bg-slate-50 rounded-2xl flex flex-wrap gap-8 items-center justify-center border border-slate-100">
        <div className="text-center">
          <p className="text-xs text-slate-400 uppercase tracking-wider font-bold">{t.totalExpenses}</p>
          <p className="text-2xl font-black text-rose-600">LKR {totalExpenses.toLocaleString()}</p>
