import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  LineChart, Line, PieChart, Pie, Cell 
} from 'recharts';

interface MonthlyChartsProps {
  t: any;
  transactions: Transaction[];
}

const COLORS = ['#4f46e5', '#10b981', '#f43f5e', '#f59e0b', '#8b5cf6', '#0ea5e9', '#ec4899'];

const MonthlyCharts: React.FC<MonthlyChartsProps> = ({ t, transactions }) => {
  const months = useMemo(() => {
    const m = Array.from(new Set(transactions.map(t => t.month)));
    return m.sort().reverse();
  }, [transactions]);

  const [selectedMonth, setSelectedMonth] = useState<string>(months[0] || '');

  const filteredTransactions = useMemo(() => {
    if (!selectedMonth || selectedMonth === 'All') return transactions;
    return transactions.filter(t => t.month === selectedMonth);
  }, [transactions, selectedMonth]);

  const categoryData = useMemo(() => {
    const data = [
      { name: t.groceries, value: 0 },
      { name: t.vegetables, value: 0 },
      { name: t.fishAndEgg, value: 0 },
      { name: t.chicken, value: 0 },
      { name: t.houseRent, value: 0 },
      { name: t.bikeExpenses, value: 0 },
      { name: t.petrol, value: 0 },
    ];

    filteredTransactions.forEach(tx => {
      data[0].value += tx.groceries;
      data[1].value += tx.vegetables;
      data[2].value += tx.fishAndEgg;
      data[3].value += tx.chicken;
      data[4].value += tx.houseRent;
      data[5].value += tx.bikeExpenses;
      data[6].value += tx.petrol;
    });

    return data.filter(d => d.value > 0);
  }, [filteredTransactions, t]);

  const trendData = useMemo(() => {
    return filteredTransactions.map(tx => ({
      date: tx.date.split('-')[2],
      amount: tx.totalExpenses
    })).sort((a, b) => parseInt(a.date) - parseInt(b.date));
  }, [filteredTransactions]);

  if (transactions.length === 0) {
    return (
      <div className="bg-white p-12 rounded-3xl border border-slate-100 text-center">
        <p className="text-slate-400">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-4 rounded-2xl border border-slate-100">
        <h2 className="text-xl font-bold text-slate-800">{t.charts}</h2>
        <select 
          className="px-4 py-2 rounded-xl border border-slate-200 bg-slate-50 focus:ring-2 focus:ring-indigo-500 outline-none"
          value={selectedMonth}
          onChange={(e) => setSelectedMonth(e.target.value)}
        >
          {months.map(m => <option key={m} value={m}>{m}</option>)}
        </select>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Bar Chart */}
        <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
          <h3 className="font-bold text-slate-700 mb-6">{t.expensesByCategory}</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={categoryData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis fontSize={12} tickLine={false} axisLine={false} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                />
                <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Line Chart */}
        <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
          <h3 className="font-bold text-slate-700 mb-6">{t.dailySpendingTrend}</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={trendData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="date" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis fontSize={12} tickLine={false} axisLine={false} />
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                />
                <Line type="monotone" dataKey="amount" stroke="#f43f5e" strokeWidth={3} dot={{r: 4, fill: '#f43f5e'}} activeDot={{r: 6}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Pie Chart */}
        <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm lg:col-span-2">
          <h3 className="font-bold text-slate-700 mb-6">{t.expenseDistribution}</h3>
          <div className="h-[350px] flex flex-col md:flex-row items-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={80}
                  outerRadius={120}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend layout="vertical" align="right" verticalAlign="middle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

