import React from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, Download } from 'lucide-react';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, onEdit, onDelete, isLoading }) => {
  const exportToCsv = () => {
    if (transactions.length === 0) return;

    const headers = ["Date", "Month", "Groceries", "Vegetables", "Fish&Egg", "Chicken", "HouseRent", "Bike", "Petrol", "CashGiven", "OpeningBal", "TotalExp", "NetBal"];
    const rows = transactions.map(tx => [
      tx.date, tx.month, tx.groceries, tx.vegetables, tx.fishAndEgg, tx.chicken, tx.houseRent, tx.bikeExpenses, tx.petrol, tx.dailyCashGiven, tx.openingBalance, tx.totalExpenses, tx.netBalance
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `finance_report_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (isLoading) {
    return <div className="p-12 text-center text-slate-400">Loading records...</div>;
  }

  if (transactions.length === 0) {
    return (
      <div className="p-12 text-center">
        <p className="text-slate-400 mb-4">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col">
      <div className="p-4 border-b border-slate-50 flex justify-end">
        <button 
          onClick={exportToCsv}
          className="flex items-center gap-2 text-indigo-600 font-bold text-sm hover:bg-indigo-50 px-4 py-2 rounded-xl transition-all"
        >
          <Download className="w-4 h-4" />
          {t.exportCsv}
        </button>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider font-bold">
              <th className="px-6 py-4">{t.date}</th>
              <th className="px-6 py-4">{t.groceries}</th>
              <th className="px-6 py-4">{t.vegetables}</th>
              <th className="px-6 py-4">{t.dailyCashGiven}</th>
              <th className="px-6 py-4">{t.totalExpenses}</th>
              <th className="px-6 py-4">{t.netBalance}</th>
              <th className="px-6 py-4 text-center">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.slice().reverse().map((tx) => (
              <tr key={tx.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date}</td>
                <td className="px-6 py-4 text-sm text-slate-600">{tx.groceries}</td>
                <td className="px-6 py-4 text-sm text-slate-600">{tx.vegetables}</td>
                <td className="px-6 py-4 text-sm font-bold text-emerald-600">{tx.dailyCashGiven}</td>
                <td className="px-6 py-4 text-sm font-bold text-rose-500">{tx.totalExpenses}</td>
                <td className="px-6 py-4 text-sm font-bold text-slate-900">{tx.netBalance}</td>
                <td className="px-6 py-4">
                  <div className="flex items-center justify-center gap-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => tx.id && onDelete(tx.id)}
                      className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

