  onSubmit: (data: Transaction) => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, email, initialData, onSubmit }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: 0,
    vegetables: 0,
    fishAndEgg: 0,
    chicken: 0,
    houseRent: 0,
    bikeExpenses: 0,
    petrol: 0,
    dailyIncome: 0,
    dailyCashGiven: 0,
    openingBalance: 0,
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries,
        vegetables: initialData.vegetables,
        fishAndEgg: initialData.fishAndEgg,
        chicken: initialData.chicken,
        houseRent: initialData.houseRent,
        bikeExpenses: initialData.bikeExpenses,
        petrol: initialData.petrol,
        dailyIncome: initialData.dailyIncome || 0,
        dailyCashGiven: initialData.dailyCashGiven,
        openingBalance: initialData.openingBalance,
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? parseFloat(value) || 0 : value
    }));
  };

  const totalExpenses = 
    formData.groceries + 
    formData.vegetables + 
    formData.fishAndEgg + 
    formData.chicken + 
    formData.houseRent + 
    formData.bikeExpenses + 
    formData.petrol;

  const netBalance = formData.openingBalance + formData.dailyIncome + formData.dailyCashGiven - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('default', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      email,
      month: monthName,
      totalExpenses,
      netBalance,
