import { Transaction, User } from '../types';

// NOTE: Replace this with your actual Google Apps Script Web App URL after deployment
const API_URL = process.env.VITE_GOOGLE_SHEETS_API || '';

const getMockData = (): Transaction[] => {
  const data = localStorage.getItem('transactions_no_auth');
  return data ? JSON.parse(data) : [];
};

const saveMockData = (data: Transaction[]) => {
  localStorage.setItem('transactions_no_auth', JSON.stringify(data));
};

export const googleSheetsService = {
  async fetchTransactions(): Promise<Transaction[]> {
    if (!API_URL) {
      return getMockData();
    }

    try {
      const response = await fetch(`${API_URL}?action=read`);
      const data = await response.json();
      return data.records || [];
    } catch (error) {
      console.error("Failed to fetch transactions", error);
      return [];
    }
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    if (!API_URL) {
      const data = getMockData();
      data.push({ ...transaction, id: Date.now().toString() });
      saveMockData(data);
      return true;
    }

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'create', ...transaction }),
      });
      return response.ok;
    } catch (error) {
      console.error("Failed to add transaction", error);
      return false;
    }
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    if (!API_URL) {
      const data = getMockData();
      const index = data.findIndex(t => t.id === id);
      if (index !== -1) {
        data[index] = { ...transaction, id };
        saveMockData(data);
        return true;
      }
      return false;
    }

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'update', id, ...transaction }),
      });
      return response.ok;
    } catch (error) {
      console.error("Failed to update transaction", error);
      return false;
    }
  },

  async deleteTransaction(id: string): Promise<boolean> {
    if (!API_URL) {
      const data = getMockData();
      const filtered = data.filter(t => t.id !== id);
      saveMockData(filtered);
      return true;
    }

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'delete', id }),
      });
      return response.ok;
    } catch (error) {
      console.error("Failed to delete transaction", error);
      return false;
    }
  },

  // Added login method to fix AuthForm.tsx error
  async login(email: string, password: string): Promise<User | null> {
    if (!API_URL) {
      return { id: '1', name: 'Guest User', email };
    }

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'login', email, password }),
      });
      const data = await response.json();
      return data.user || null;
    } catch (error) {
      console.error("Failed to login", error);
      return null;
    }
  },

  // Added register method to fix AuthForm.tsx error
  async register(name: string, email: string, password: string): Promise<User | null> {
    if (!API_URL) {
      return { id: '1', name, email };
    }

    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'register', name, email, password }),
      });
      const data = await response.json();
      return data.user || null;
    } catch (error) {
      console.error("Failed to register", error);
      return null;
    }
  }
};

import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  PieChart, Pie, Cell 
} from 'recharts';

interface MonthlyChartsProps {
  t: any;
  transactions: Transaction[];
}

const COLORS = ['#4f46e5', '#10b981', '#f43f5e', '#f59e0b', '#8b5cf6', '#0ea5e9', '#ec4899'];

const MonthlyCharts: React.FC<MonthlyChartsProps> = ({ t, transactions }) => {
  const months = useMemo(() => {
    const m = Array.from(new Set(transactions.map(t => t.month)));
    return m.sort().reverse();
  }, [transactions]);

  const [selectedMonth, setSelectedMonth] = useState<string>(months[0] || '');

  const filteredTransactions = useMemo(() => {
    if (!selectedMonth || selectedMonth === 'All') return transactions;
    return transactions.filter(t => t.month === selectedMonth);
  }, [transactions, selectedMonth]);

  const categoryData = useMemo(() => {
    const data = [
      { name: t.groceries, value: 0 },
      { name: t.vegetables, value: 0 },
      { name: t.fishAndEgg, value: 0 },
      { name: t.chicken, value: 0 },
      { name: t.houseRent, value: 0 },
      { name: t.bikeExpenses, value: 0 },
      { name: t.petrol, value: 0 },
    ];

    filteredTransactions.forEach(tx => {
      data[0].value += tx.groceries;
      data[1].value += tx.vegetables;
      data[2].value += tx.fishAndEgg;
      data[3].value += tx.chicken;
      data[4].value += tx.houseRent;
      data[5].value += tx.bikeExpenses;
      data[6].value += tx.petrol;
    });

    return data.filter(d => d.value > 0);
  }, [filteredTransactions, t]);

  if (transactions.length === 0) {
    return (
      <div className="bg-white p-12 rounded-3xl border border-slate-100 text-center">
        <p className="text-slate-400">{t.noData}</p>
      </div>
    );
  }

