import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';

interface TransactionFormProps {
  t: any;
  initialData?: Transaction | null;
  onSubmit: (data: Transaction) => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, initialData, onSubmit }) => {
  // Use empty strings instead of 0 for initial state to "remove 0" from UI
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: '' as any,
    vegetables: '' as any,
    fishAndEgg: '' as any,
    chicken: '' as any,
    houseRent: '' as any,
    bikeExpenses: '' as any,
    petrol: '' as any,
    dailyIncome: '' as any,
    dailyCashGiven: '' as any,
    openingBalance: '' as any,
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries || '',
        vegetables: initialData.vegetables || '',
        fishAndEgg: initialData.fishAndEgg || '',
        chicken: initialData.chicken || '',
        houseRent: initialData.houseRent || '',
        bikeExpenses: initialData.bikeExpenses || '',
        petrol: initialData.petrol || '',
        dailyIncome: initialData.dailyIncome || '',
        dailyCashGiven: initialData.dailyCashGiven || '',
        openingBalance: initialData.openingBalance || '',
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    // Keep as string if it's an empty input, otherwise parse as number
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? (value === '' ? '' : parseFloat(value)) : value
    }));
  };

  // Safe number conversion for calculations
  const val = (v: any) => parseFloat(v) || 0;

  const totalExpenses = 
    val(formData.groceries) + 
    val(formData.vegetables) + 
    val(formData.fishAndEgg) + 
    val(formData.chicken) + 
    val(formData.houseRent) + 
    val(formData.bikeExpenses) + 
    val(formData.petrol);

  const netBalance = val(formData.openingBalance) + val(formData.dailyIncome) + val(formData.dailyCashGiven) - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('default', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      groceries: val(formData.groceries),
      vegetables: val(formData.vegetables),
      fishAndEgg: val(formData.fishAndEgg),
      chicken: val(formData.chicken),
      houseRent: val(formData.houseRent),
      bikeExpenses: val(formData.bikeExpenses),
      petrol: val(formData.petrol),
      dailyIncome: val(formData.dailyIncome),
      dailyCashGiven: val(formData.dailyCashGiven),
      openingBalance: val(formData.openingBalance),
      month: monthName,
      totalExpenses,
      netBalance,
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.date}</label>
          <input
            type="date"
            name="date"
            required
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.date}
            onChange={handleChange}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.openingBalance}</label>
          <input
            type="number"
            name="openingBalance"
            placeholder="0"
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.openingBalance}
            onChange={handleChange}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {[
          { name: 'dailyIncome', label: t.dailyIncome, highlight: true },
          { name: 'dailyCashGiven', label: t.dailyCashGiven, highlight: true },
          { name: 'groceries', label: t.groceries },
          { name: 'vegetables', label: t.vegetables },
          { name: 'fishAndEgg', label: t.fishAndEgg },
          { name: 'chicken', label: t.chicken },
          { name: 'houseRent', label: t.houseRent },
          { name: 'bikeExpenses', label: t.bikeExpenses },
          { name: 'petrol', label: t.petrol },
        ].map(field => (
          <div key={field.name}>
            <label className={`block text-sm font-semibold mb-1 ${field.highlight ? 'text-indigo-700' : 'text-slate-700'}`}>{field.label}</label>
            <input
              type="number"
              name={field.name}
