      <button
        type="submit"
        className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-[0.99] transition-all"
      >
        {t.save}
      </button>
    </form>
  );
};

