import React, { useState, useMemo } from 'react';
import { Transaction } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  PieChart, Pie, Cell 
} from 'recharts';

interface MonthlyChartsProps {
  t: any;
  transactions: Transaction[];
}

const COLORS = ['#4f46e5', '#10b981', '#f43f5e', '#f59e0b', '#8b5cf6'];

const MonthlyCharts: React.FC<MonthlyChartsProps> = ({ t, transactions }) => {
  const months = useMemo(() => {
    const m = Array.from(new Set(transactions.map(t => t.month)));
    return m.sort().reverse();
  }, [transactions]);

  const [selectedMonth, setSelectedMonth] = useState<string>(months[0] || '');

  const filteredTransactions = useMemo(() => {
    if (!selectedMonth || selectedMonth === 'All') return transactions;
    return transactions.filter(t => t.month === selectedMonth);
  }, [transactions, selectedMonth]);

  const categoryData = useMemo(() => {
    const data = [
      { name: t.groceries, value: 0 },
      { name: t.vegetables, value: 0 },
      { name: t.fishAndEgg, value: 0 },
      { name: t.chicken, value: 0 },
      { name: t.houseRent, value: 0 },
    ];

    filteredTransactions.forEach(tx => {
      data[0].value += tx.groceries;
      data[1].value += tx.vegetables;
      data[2].value += tx.fishAndEgg;
      data[3].value += tx.chicken;
      data[4].value += tx.houseRent;
    });

    return data.filter(d => d.value > 0);
  }, [filteredTransactions, t]);

  if (transactions.length === 0) {
    return (
      <div className="bg-white p-12 rounded-3xl border border-slate-100 text-center">
        <p className="text-slate-400">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-4 rounded-2xl border border-slate-100">
        <h2 className="text-xl font-bold text-slate-800">{t.charts}</h2>
        <select 
          className="px-4 py-2 rounded-xl border border-slate-200 bg-slate-50 focus:ring-2 focus:ring-indigo-500 outline-none"
          value={selectedMonth}
          onChange={(e) => setSelectedMonth(e.target.value)}
        >
          {months.map(m => <option key={m} value={m}>{m}</option>)}
        </select>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
          <h3 className="font-bold text-slate-700 mb-6">{t.expensesByCategory}</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={categoryData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis fontSize={12} tickLine={false} axisLine={false} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                />
                <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
          <h3 className="font-bold text-slate-700 mb-6">{t.expenseDistribution}</h3>
          <div className="h-[300px] flex flex-col items-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend layout="horizontal" align="center" verticalAlign="bottom" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MonthlyCharts;

import React from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, Download } from 'lucide-react';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, onEdit, onDelete, isLoading }) => {
  const exportToCsv = () => {
    if (transactions.length === 0) return;

    const headers = ["Date", "Month", "Groceries", "Vegetables", "Fish&Egg", "Chicken", "HouseRent", "DailyIncome", "CashReceived", "OpeningBal", "TotalExp", "NetBal"];
    const rows = transactions.map(tx => [
      tx.date, tx.month, tx.groceries, tx.vegetables, tx.fishAndEgg, tx.chicken, tx.houseRent, tx.dailyIncome, tx.dailyCashGiven, tx.openingBalance, tx.totalExpenses, tx.netBalance
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `finance_report_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (isLoading) {
    return <div className="p-12 text-center text-slate-400">Loading records...</div>;
  }

  if (transactions.length === 0) {
    return (
      <div className="p-12 text-center">
        <p className="text-slate-400 mb-4">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col">
      <div className="p-4 border-b border-slate-50 flex justify-end">
        <button 
          onClick={exportToCsv}
          className="flex items-center gap-2 text-indigo-600 font-bold text-sm hover:bg-indigo-50 px-4 py-2 rounded-xl transition-all"
        >
          <Download className="w-4 h-4" />
          {t.exportCsv}
        </button>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[800px]">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase tracking-wider font-black">
              <th className="px-6 py-4">{t.date}</th>
              <th className="px-6 py-4">{t.dailyIncome}</th>
              <th className="px-6 py-4">{t.dailyCashGiven}</th>
              <th className="px-6 py-4">{t.totalExpenses}</th>
              <th className="px-6 py-4">{t.netBalance}</th>
              <th className="px-6 py-4 text-center">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.slice().reverse().map((tx) => (
              <tr key={tx.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date}</td>
                <td className="px-6 py-4 text-sm font-bold text-emerald-600">LKR {tx.dailyIncome?.toLocaleString()}</td>
                <td className="px-6 py-4 text-sm text-slate-600 font-medium">LKR {tx.dailyCashGiven?.toLocaleString()}</td>
                <td className="px-6 py-4 text-sm font-bold text-rose-500">LKR {tx.totalExpenses?.toLocaleString()}</td>
                <td className="px-6 py-4 text-sm font-black text-slate-900">LKR {tx.netBalance?.toLocaleString()}</td>
                <td className="px-6 py-4">
                  <div className="flex items-center justify-center gap-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => tx.id && onDelete(tx.id)}
                      className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useState, useMemo } from 'react';
import { Transaction, MonthlySummary } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import { Plus, X, Calendar, ClipboardList } from 'lucide-react';

interface DashboardProps {
  activeTab: 'dashboard' | 'history' | 'charts';
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  isLoading 
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('default', { month: 'long', year: 'numeric' });
  }, []);

  const [selectedMonth, setSelectedMonth] = useState<string>(currentMonthName);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => monthsSet.add(tx.month));
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const monthlySummary: MonthlySummary[] = useMemo(() => {
    const summaryMap: Record<string, MonthlySummary> = {};

    transactions.forEach((tx) => {
      const monthKey = tx.month;
      if (!summaryMap[monthKey]) {
        summaryMap[monthKey] = {
          month: monthKey,
          totalGroceries: 0,
          totalVegetables: 0,
          totalFishAndEgg: 0,
          totalChicken: 0,
          totalHouseRent: 0,
          totalExpenses: 0,
          totalIncome: 0,
          totalCashGiven: 0,
          openingBalance: tx.openingBalance,
          closingBalance: 0
        };
      }
      summaryMap[monthKey].totalGroceries += tx.groceries;
      summaryMap[monthKey].totalVegetables += tx.vegetables;
      summaryMap[monthKey].totalFishAndEgg += tx.fishAndEgg;
      summaryMap[monthKey].totalChicken += tx.chicken;
      summaryMap[monthKey].totalHouseRent += tx.houseRent;
      summaryMap[monthKey].totalExpenses += tx.totalExpenses;
      summaryMap[monthKey].totalIncome += (tx.dailyIncome || 0);
      summaryMap[monthKey].totalCashGiven += tx.dailyCashGiven;
      summaryMap[monthKey].closingBalance = tx.netBalance; 
    });

    return Object.values(summaryMap).sort((a, b) => {
      const dateA = new Date(a.month);
      const dateB = new Date(b.month);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions]);

  const filteredStats = useMemo(() => {
    const monthTx = transactions.filter(tx => tx.month === selectedMonth);
    const totalSpent = monthTx.reduce((sum, tx) => sum + tx.totalExpenses, 0);
    const totalReceived = monthTx.reduce((sum, tx) => sum + (tx.dailyCashGiven + (tx.dailyIncome || 0)), 0);
    const lastBalance = monthTx.length > 0 ? monthTx[monthTx.length - 1].netBalance : 0;

    return { totalSpent, totalReceived, lastBalance };
  }, [transactions, selectedMonth]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleCloseForm = () => {
    setShowAddForm(false);
    setEditingTransaction(null);
  };

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-3xl border border-slate-100 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-50 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600" />
          </div>
          <div>
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-wider">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 outline-none cursor-pointer hover:text-indigo-600 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m}>{m}</option>
              ))}
            </select>
          </div>
        </div>
        <button 
          onClick={() => setShowAddForm(true)}
          className="w-full sm:w-auto bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addRecord}
        </button>
      </div>

      {activeTab === 'dashboard' && (
        <>
          <StatsOverview t={t} stats={filteredStats} />

          <div className="mt-8 bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center gap-3">
              <ClipboardList className="w-6 h-6 text-indigo-600" />
              <h2 className="text-xl font-bold text-slate-800">{t.dailyWiseReport} ({selectedMonth})</h2>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[1000px]">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.dailyIncome}</th>
                    <th className="px-6 py-4">{t.dailyCashGiven}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30">{t.netBalance}</th>
                    <th className="px-6 py-4 text-slate-400 font-bold border-l border-slate-100">Breakdown (G / V / F / C / H)</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {currentMonthTransactions.map((tx) => (
                    <tr key={tx.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600">{tx.dailyIncome?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-medium text-slate-600">{tx.dailyCashGiven?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500">{tx.totalExpenses?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 bg-indigo-50/20">{tx.netBalance?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-[10px] text-slate-400 font-medium border-l border-slate-100">
                        {tx.groceries} / {tx.vegetables} / {tx.fishAndEgg} / {tx.chicken} / {tx.houseRent}
                      </td>
                    </tr>
                  ))}
                  {currentMonthTransactions.length === 0 && (
                    <tr>
                      <td colSpan={6} className="px-6 py-12 text-center text-slate-400 font-medium">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>

          <div className="mt-8">
            <h2 className="text-xl font-bold text-slate-800 mb-4">{t.summary}</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {monthlySummary.map((sum) => (
                  <div 
                    key={sum.month} 
                    onClick={() => setSelectedMonth(sum.month)}
                    className={`bg-white p-6 rounded-3xl shadow-sm border transition-all cursor-pointer ${selectedMonth === sum.month ? 'border-indigo-500 ring-2 ring-indigo-50' : 'border-slate-100 hover:shadow-md'}`}
                  >
                    <div className="flex justify-between items-center mb-4">
                       <h3 className="font-bold text-lg text-indigo-600">{sum.month}</h3>
                       {sum.month === currentMonthName && (
                         <span className="bg-emerald-50 text-emerald-700 text-[10px] font-black px-2 py-0.5 rounded-full uppercase">Current</span>
                       )}
                    </div>
                    <div className="space-y-2">
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.totalExpenses}</span>
                         <span className="font-semibold text-rose-500">LKR {sum.totalExpenses.toLocaleString()}</span>
                       </div>
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.totalIncome}</span>
                         <span className="font-semibold text-emerald-600">LKR {sum.totalIncome.toLocaleString()}</span>
                       </div>
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.dailyCashGiven}</span>
                         <span className="font-semibold text-emerald-600">LKR {sum.totalCashGiven.toLocaleString()}</span>
                       </div>
                       <div className="pt-2 border-t border-slate-50 flex justify-between">
                         <span className="font-bold text-slate-700">{t.netBalance}</span>
                         <span className="font-bold text-slate-900">LKR {sum.closingBalance.toLocaleString()}</span>
                       </div>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        </>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800">{t.history} ({selectedMonth})</h2>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions.filter(tx => tx.month === selectedMonth)} 
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
          />
        </div>
      )}

      {activeTab === 'charts' && (
        <MonthlyCharts t={t} transactions={transactions} />
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={handleCloseForm}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  handleCloseForm();
                }} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

/**
 * Personal Finance Tracker - Google Apps Script Backend (No Authentication)
 * 
 * 1. Open Google Sheets
 * 2. Extensions -> Apps Script
 * 3. Paste this code
 * 4. Deploy -> New Deployment -> Web App
 * 5. Set 'Who has access' to 'Anyone'
 * 6. Copy the Web App URL to your environment variable
 */

const SHEET_NAME = 'Transactions';

function setup() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_NAME);
    sheet.appendRow([
      'ID', 'Date', 'Month', 'Groceries', 'Vegetables', 
      'FishAndEgg', 'Chicken', 'HouseRent',
      'DailyIncome', 'DailyCashGiven', 'OpeningBalance', 'TotalExpenses', 'NetBalance'
    ]);
  }
}

function doPost(e) {
  const data = JSON.parse(e.postData.contents);
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);
  const action = data.action;

  if (action === 'create') {
    const id = Utilities.getUuid();
    sheet.appendRow([
      id, data.date, data.month, data.groceries, data.vegetables,
      data.fishAndEgg, data.chicken, data.houseRent,
      data.dailyIncome || 0, data.dailyCashGiven, data.openingBalance, data.totalExpenses, data.netBalance
    ]);
    return ContentService.createTextOutput(JSON.stringify({ status: 'success', id })).setMimeType(ContentService.MimeType.JSON);
  }

  if (action === 'update') {
    const values = sheet.getDataRange().getValues();
    for (let i = 1; i < values.length; i++) {
      if (values[i][0] == data.id) {
        sheet.getRange(i + 1, 1, 1, 13).setValues([[
          data.id, data.date, data.month, data.groceries, data.vegetables,
          data.fishAndEgg, data.chicken, data.houseRent,
          data.dailyIncome || 0, data.dailyCashGiven, data.openingBalance, data.totalExpenses, data.netBalance
        ]]);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
  }

  if (action === 'delete') {
    const values = sheet.getDataRange().getValues();
    for (let i = 1; i < values.length; i++) {
      if (values[i][0] == data.id) {
        sheet.deleteRow(i + 1);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);
  const values = sheet.getDataRange().getValues();
  const headers = values[0];
  const records = [];

  for (let i = 1; i < values.length; i++) {
    const record = {};
    headers.forEach((header, index) => {
      let key = header.charAt(0).toLowerCase() + header.slice(1);
      record[key] = values[i][index];
    });
    records.push(record);
  }

  return ContentService.createTextOutput(JSON.stringify({ records })).setMimeType(ContentService.MimeType.JSON);
}

import React from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, Download } from 'lucide-react';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, onEdit, onDelete, isLoading }) => {
  const exportToCsv = () => {
    if (transactions.length === 0) return;

    const headers = ["Date", "Month", "Groceries", "Vegetables", "Fish&Egg", "Chicken", "HouseRent", "DailyIncome", "CashReceived", "OpeningBal", "TotalExp", "NetBal"];
    const rows = transactions.map(tx => [
      tx.date, tx.month, tx.groceries, tx.vegetables, tx.fishAndEgg, tx.chicken, tx.houseRent, tx.dailyIncome, tx.dailyCashGiven, tx.openingBalance, tx.totalExpenses, tx.netBalance
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `finance_report_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (isLoading) {
    return <div className="p-12 text-center text-slate-400">Loading records...</div>;
  }

  if (transactions.length === 0) {
    return (
      <div className="p-12 text-center">
        <p className="text-slate-400 mb-4">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col">
      <div className="p-4 border-b border-slate-50 flex justify-end">
        <button 
          onClick={exportToCsv}
          className="flex items-center gap-2 text-indigo-600 font-bold text-sm hover:bg-indigo-50 px-4 py-2 rounded-xl transition-all"
        >
          <Download className="w-4 h-4" />
          {t.exportCsv}
        </button>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[1000px]">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase tracking-wider font-black">
              <th className="px-6 py-4">{t.date}</th>
              <th className="px-6 py-4">{t.dailyIncome}</th>
              <th className="px-6 py-4">{t.dailyCashGiven}</th>
              <th className="px-6 py-4">{t.totalExpenses}</th>
              <th className="px-6 py-4">{t.netBalance}</th>
              <th className="px-6 py-4 text-slate-400">Breakdown (G/V/F/C/H)</th>
              <th className="px-6 py-4 text-center">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.slice().reverse().map((tx) => (
              <tr key={tx.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 text-sm font-bold text-emerald-600">LKR {tx.dailyIncome?.toLocaleString()}</td>
                <td className="px-6 py-4 text-sm text-slate-600 font-medium">LKR {tx.dailyCashGiven?.toLocaleString()}</td>
                <td className="px-6 py-4 text-sm font-bold text-rose-500">LKR {tx.totalExpenses?.toLocaleString()}</td>
                <td className="px-6 py-4 text-sm font-black text-slate-900">LKR {tx.netBalance?.toLocaleString()}</td>
                <td className="px-6 py-4 text-[10px] text-slate-400 font-medium">
                   {tx.groceries} / {tx.vegetables} / {tx.fishAndEgg} / {tx.chicken} / {tx.houseRent}
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center justify-center gap-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => tx.id && onDelete(tx.id)}
                      className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

