          <h1 className="font-bold text-lg text-slate-800 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'dashboard' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            {t.dashboard}
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'history' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <History className="w-5 h-5" />
            {t.history}
          </button>
        </div>

        <div className="mt-auto pt-6 border-t border-slate-100">
          <button 
            onClick={toggleLanguage}
            className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 hover:text-indigo-600 font-medium transition-colors"
          >
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
        </div>
      </nav>

      {/* Mobile Top Nav */}
      <header className="md:hidden bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between sticky top-0 z-30">
        <div className="flex items-center gap-2">
          <Wallet className="w-6 h-6 text-indigo-600" />
          <h1 className="font-bold text-sm text-slate-800">{t.title}</h1>
        </div>
        <button onClick={toggleLanguage} className="p-2 text-slate-500 hover:bg-slate-100 rounded-lg transition-colors">
          <Globe className="w-5 h-5"/>
        </button>
      </header>

      {/* Main Content */}
      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-4 md:p-8">
          <Dashboard 
            activeTab={activeTab} 
            t={t} 
            transactions={transactions} 
            onAdd={onAddTransaction}
            onUpdate={async (id, data) => {
               await googleSheetsService.updateTransaction(id, data);
               loadData();
            }}
            onDelete={async (id) => {
               if(confirm(t.confirmDelete)) {
                 await googleSheetsService.deleteTransaction(id);
                 loadData();
               }
            }}
            isLoading={isLoading}
          />
        </div>
      </main>

      {/* Mobile Bottom Nav */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex items-center justify-around p-3 z-30 shadow-[0_-4px_12px_rgba(0,0,0,0.05)]">
