    const lastBalance = monthTx.length > 0 ? monthTx[monthTx.length - 1].netBalance : 0;

    return { totalSpent, totalReceived, lastBalance };
  }, [transactions, selectedMonth]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleCloseForm = () => {
    setShowAddForm(false);
    setEditingTransaction(null);
  };

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-3xl border border-slate-100 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-50 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600" />
          </div>
          <div>
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-wider">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 outline-none cursor-pointer hover:text-indigo-600 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m}>{m}</option>
              ))}
            </select>
          </div>
        </div>
        <button 
          onClick={() => setShowAddForm(true)}
          className="w-full sm:w-auto bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addRecord}
        </button>
      </div>

      {activeTab === 'dashboard' && (
        <>
          <StatsOverview t={t} stats={filteredStats} />
          <div className="mt-8">
            <h2 className="text-xl font-bold text-slate-800 mb-4">{t.summary}</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {monthlySummary.map((sum) => (
                  <div 
                    key={sum.month} 
                    onClick={() => setSelectedMonth(sum.month)}
                    className={`bg-white p-6 rounded-3xl shadow-sm border transition-all cursor-pointer ${selectedMonth === sum.month ? 'border-indigo-500 ring-2 ring-indigo-50' : 'border-slate-100 hover:shadow-md'}`}
                  >
                    <div className="flex justify-between items-center mb-4">
                       <h3 className="font-bold text-lg text-indigo-600">{sum.month}</h3>
                       {sum.month === currentMonthName && (
                         <span className="bg-emerald-50 text-emerald-700 text-[10px] font-black px-2 py-0.5 rounded-full uppercase">Current</span>
                       )}
                    </div>
                    <div className="space-y-2">
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.totalExpenses}</span>
                         <span className="font-semibold text-rose-500">LKR {sum.totalExpenses.toLocaleString()}</span>
                       </div>
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.totalIncome}</span>
                         <span className="font-semibold text-emerald-600">LKR {sum.totalIncome.toLocaleString()}</span>
                       </div>
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.dailyCashGiven}</span>
                         <span className="font-semibold text-emerald-600">LKR {sum.totalCashGiven.toLocaleString()}</span>
                       </div>
                       <div className="pt-2 border-t border-slate-50 flex justify-between">
                         <span className="font-bold text-slate-700">{t.netBalance}</span>
                         <span className="font-bold text-slate-900">LKR {sum.closingBalance.toLocaleString()}</span>
                       </div>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center gap-3 mb-6">
              <div className="p-2 bg-indigo-100 rounded-xl">
                <BarChart3 className="w-6 h-6 text-indigo-700" />
              </div>
              <h2 className="text-2xl font-black text-slate-800">{t.charts} - {selectedMonth}</h2>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>

          <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center gap-3 bg-slate-50/50">
              <ClipboardList className="w-6 h-6 text-indigo-600" />
              <h2 className="text-xl font-bold text-slate-800">{t.dailyWiseReport}</h2>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[1000px]">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.dailyIncome}</th>
                    <th className="px-6 py-4">{t.dailyCashGiven}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 text-indigo-700">{t.netBalance}</th>
                    <th className="px-6 py-4 text-slate-400 font-bold border-l border-slate-100">Daily Breakdown (G / V / F / C / H)</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {currentMonthTransactions.map((tx) => (
                    <tr key={tx.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600">{tx.dailyIncome?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-medium text-slate-600">{tx.dailyCashGiven?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500">{tx.totalExpenses?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 bg-indigo-50/20">{tx.netBalance?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-[10px] text-slate-400 font-medium border-l border-slate-100">
                        {tx.groceries} / {tx.vegetables} / {tx.fishAndEgg} / {tx.chicken} / {tx.houseRent}
                      </td>
                    </tr>
                  ))}
                  {currentMonthTransactions.length === 0 && (
                    <tr>
                      <td colSpan={6} className="px-6 py-12 text-center text-slate-400 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
                {currentMonthTransactions.length > 0 && (
                  <tfoot className="bg-slate-50/50 border-t border-slate-200">
                    <tr className="font-bold text-slate-900">
                      <td className="px-6 py-4 text-sm uppercase">Monthly Total</td>
                      <td className="px-6 py-4 text-sm text-emerald-700">{currentMonthTransactions.reduce((s,t)=>s+(t.dailyIncome||0),0).toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm text-slate-700">{currentMonthTransactions.reduce((s,t)=>s+t.dailyCashGiven,0).toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm text-rose-600">{currentMonthTransactions.reduce((s,t)=>s+t.totalExpenses,0).toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-700 bg-indigo-50/40">LKR {currentMonthTransactions[currentMonthTransactions.length-1].netBalance.toLocaleString()}</td>
                      <td className="px-6 py-4 border-l border-slate-100"></td>
                    </tr>
                  </tfoot>
                )}
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800">{t.history} ({selectedMonth})</h2>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions.filter(tx => tx.month === selectedMonth)} 
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col scale-in-center">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={handleCloseForm}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  handleCloseForm();
                }} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Transaction, Language } from './types';
import { translations } from './translations';
import { googleSheetsService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import { Globe, Wallet, LayoutDashboard, History, BarChart3 } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  const t = translations[lang];

  useEffect(() => {
    loadData();
    const savedLang = localStorage.getItem('lang');
    if (savedLang) setLang(savedLang as Language);
  }, []);

  const loadData = async () => {
    setIsLoading(true);
    const data = await googleSheetsService.fetchTransactions();
    setTransactions(data);
    setIsLoading(false);
  };

  const toggleLanguage = () => {
    const newLang = lang === 'en' ? 'si' : 'en';
    setLang(newLang);
    localStorage.setItem('lang', newLang);
  };

  const onAddTransaction = async (data: Transaction) => {
    const success = await googleSheetsService.addTransaction(data);
    if (success) {
      loadData();
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0">
      {/* Sidebar / Desktop Nav */}
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white border-r border-slate-200 p-6 z-20">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'dashboard' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            {t.dashboard}
          </button>
          <button 
            onClick={() => setActiveTab('analytics')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'analytics' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <BarChart3 className="w-5 h-5" />
            {t.charts}
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'history' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <History className="w-5 h-5" />
            {t.history}
          </button>
        </div>

        <div className="mt-auto pt-6 border-t border-slate-100">
          <button 
            onClick={toggleLanguage}
            className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 hover:text-indigo-600 font-medium transition-colors"
          >
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
        </div>
      </nav>

      {/* Mobile Top Nav */}
      <header className="md:hidden bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between sticky top-0 z-30">
        <div className="flex items-center gap-2">
          <Wallet className="w-6 h-6 text-indigo-600" />
          <h1 className="font-bold text-sm text-slate-800">{t.title}</h1>
        </div>
        <button onClick={toggleLanguage} className="p-2 text-slate-500 hover:bg-slate-100 rounded-lg transition-colors">
          <Globe className="w-5 h-5"/>
        </button>
      </header>

      {/* Main Content */}
      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-4 md:p-8">
          <Dashboard 
            activeTab={activeTab} 
            setActiveTab={setActiveTab}
            t={t} 
            transactions={transactions} 
            onAdd={onAddTransaction}
            onUpdate={async (id, data) => {
               await googleSheetsService.updateTransaction(id, data);
               loadData();
            }}
            onDelete={async (id) => {
               if(confirm(t.confirmDelete)) {
                 await googleSheetsService.deleteTransaction(id);
                 loadData();
               }
            }}
            isLoading={isLoading}
          />
        </div>
      </main>

      {/* Mobile Bottom Nav */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex items-center justify-around p-3 z-30 shadow-[0_-4px_12px_rgba(0,0,0,0.05)]">
        <button 
          onClick={() => setActiveTab('dashboard')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'dashboard' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-[10px] font-bold">{t.dashboard}</span>
        </button>
        <button 
          onClick={() => setActiveTab('analytics')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'analytics' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <BarChart3 className="w-6 h-6" />
          <span className="text-[10px] font-bold">{t.charts}</span>
        </button>
        <button 
          onClick={() => setActiveTab('history')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'history' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <History className="w-6 h-6" />
          <span className="text-[10px] font-bold">{t.history}</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Transaction, MonthlySummary } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight } from 'lucide-react';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  isLoading 
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('default', { month: 'long', year: 'numeric' });
  }, []);

  const [selectedMonth, setSelectedMonth] = useState<string>(currentMonthName);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => monthsSet.add(tx.month));
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const monthlySummary: MonthlySummary[] = useMemo(() => {
    const summaryMap: Record<string, MonthlySummary> = {};

    transactions.forEach((tx) => {
      const monthKey = tx.month;
      if (!summaryMap[monthKey]) {
        summaryMap[monthKey] = {
          month: monthKey,
          totalGroceries: 0,
          totalVegetables: 0,
          totalFishAndEgg: 0,
          totalChicken: 0,
          totalHouseRent: 0,
          totalExpenses: 0,
          totalIncome: 0,
          totalCashGiven: 0,
          openingBalance: tx.openingBalance,
          closingBalance: 0
        };
      }
      summaryMap[monthKey].totalGroceries += tx.groceries;
      summaryMap[monthKey].totalVegetables += tx.vegetables;
      summaryMap[monthKey].totalFishAndEgg += tx.fishAndEgg;
      summaryMap[monthKey].totalChicken += tx.chicken;
      summaryMap[monthKey].totalHouseRent += tx.houseRent;
      summaryMap[monthKey].totalExpenses += tx.totalExpenses;
      summaryMap[monthKey].totalIncome += (tx.dailyIncome || 0);
      summaryMap[monthKey].totalCashGiven += tx.dailyCashGiven;
      summaryMap[monthKey].closingBalance = tx.netBalance; 
    });

    return Object.values(summaryMap).sort((a, b) => {
      const dateA = new Date(a.month);
      const dateB = new Date(b.month);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions]);

  const filteredStats = useMemo(() => {
    const monthTx = transactions.filter(tx => tx.month === selectedMonth);
    const totalSpent = monthTx.reduce((sum, tx) => sum + tx.totalExpenses, 0);
    const totalReceived = monthTx.reduce((sum, tx) => sum + (tx.dailyCashGiven + (tx.dailyIncome || 0)), 0);
    const lastBalance = monthTx.length > 0 ? monthTx[monthTx.length - 1].netBalance : 0;

    return { totalSpent, totalReceived, lastBalance };
  }, [transactions, selectedMonth]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleCloseForm = () => {
    setShowAddForm(false);
    setEditingTransaction(null);
  };

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const recentTransactions = useMemo(() => {
    return currentMonthTransactions.slice().reverse().slice(0, 5);
  }, [currentMonthTransactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-3xl border border-slate-100 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-50 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600" />
          </div>
          <div>
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-wider">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 outline-none cursor-pointer hover:text-indigo-600 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m}>{m}</option>
              ))}
            </select>
          </div>
        </div>
        <button 
          onClick={() => setShowAddForm(true)}
          className="w-full sm:w-auto bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
        >
          <Plus className="w-5 h-5" />
          {t.addRecord}
        </button>
      </div>

      {activeTab === 'dashboard' && (
        <>
          <StatsOverview t={t} stats={filteredStats} />

          <div className="mt-8 bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <ClipboardList className="w-6 h-6 text-indigo-600" />
                <h2 className="text-xl font-bold text-slate-800">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-sm font-bold text-indigo-600 hover:text-indigo-700 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[800px]">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.dailyIncome}</th>
                    <th className="px-6 py-4">{t.dailyCashGiven}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 text-indigo-700">{t.netBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {recentTransactions.map((tx) => (
                    <tr key={tx.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600">LKR {tx.dailyIncome?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-medium text-slate-600">LKR {tx.dailyCashGiven?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500">LKR {tx.totalExpenses?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 bg-indigo-50/20">LKR {tx.netBalance?.toLocaleString()}</td>
                    </tr>
                  ))}
                  {recentTransactions.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-12 text-center text-slate-400 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>

          <div className="mt-8">
            <h2 className="text-xl font-bold text-slate-800 mb-4">{t.summary}</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {monthlySummary.map((sum) => (
                  <div 
                    key={sum.month} 
