import { Transaction, User } from '../types';

const API_URL = 'https://script.google.com/macros/s/AKfycbw8Qo64ZJZuAptrshwpRmvCiv0Vw3Vv9ks4HR8XDU-kBNc_di3KDm0UR5ftdDTwGcVl/exec';

const getMockData = (): Transaction[] => {
  const data = localStorage.getItem('transactions_data_v2');
  return data ? JSON.parse(data) : [];
};

const saveMockData = (data: Transaction[]) => {
  localStorage.setItem('transactions_data_v2', JSON.stringify(data));
};

export const googleSheetsService = {
  async fetchTransactions(): Promise<Transaction[]> {
    try {
      const response = await fetch(`${API_URL}?action=read`);
      if (!response.ok) throw new Error('Network response was not ok');
      const data = await response.json();
      return data.records || [];
    } catch (error) {
      console.error("Failed to fetch transactions, using local storage", error);
      return getMockData();
    }
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    try {
      const payload = {
        action: 'create',
        ...transaction,
        timestamp: new Date().toISOString()
      };

      const response = await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors', // Common for Google Apps Script Web Apps
        body: JSON.stringify(payload),
      });

      // Update local storage too for immediate feedback or if no-cors obscures result
      const data = getMockData();
      data.push({ ...transaction, id: Date.now().toString() });
      saveMockData(data);

      return true;
    } catch (error) {
      console.error("Failed to add transaction", error);
      return false;
    }
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify({ action: 'update', id, ...transaction }),
      });

      const data = getMockData();
      const index = data.findIndex(t => t.id === id);
      if (index !== -1) {
        data[index] = { ...transaction, id };
        saveMockData(data);
      }
      return true;
    } catch (error) {
      console.error("Failed to update transaction", error);
      return false;
    }
  },

  async deleteTransaction(id: string): Promise<boolean> {
    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify({ action: 'delete', id }),
      });

      const data = getMockData();
      const filtered = data.filter(t => t.id !== id);
      saveMockData(filtered);
      return true;
    } catch (error) {
      console.error("Failed to delete transaction", error);
      return false;
    }
  }
};

