                       <div className="pt-2 border-t border-slate-50 flex justify-between">
                         <span className="font-bold text-slate-700">{t.totalBalance}</span>
                         <span className="font-bold text-slate-900">LKR {sum.totalBalance.toLocaleString()}</span>
                       </div>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center gap-3 mb-6">
              <div className="p-2 bg-indigo-100 rounded-xl">
                <BarChart3 className="w-6 h-6 text-indigo-700" />
              </div>
              <h2 className="text-2xl font-black text-slate-800">{t.charts} - {selectedMonth}</h2>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>

          <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center gap-3 bg-slate-50/50">
              <ClipboardList className="w-6 h-6 text-indigo-600" />
              <h2 className="text-xl font-bold text-slate-800">{t.dailyWiseReport}</h2>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[1000px]">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.dailyCash}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 text-indigo-700">{t.totalBalance}</th>
                    <th className="px-6 py-4 text-slate-400 font-bold border-l border-slate-100">Breakdown (G / V / F / C / H)</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {currentMonthTransactions.map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600">{tx.dailyCash?.toLocaleString()}</td>
