      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col scale-in-center">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={handleCloseForm}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  handleCloseForm();
                }} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';

interface TransactionFormProps {
  t: any;
  initialData?: Transaction | null;
  onSubmit: (data: Transaction) => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, initialData, onSubmit }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: '' as any,
    vegetables: '' as any,
    fishEgg: '' as any,
    chicken: '' as any,
    houseRent: '' as any,
    dailyCash: '' as any,
    broughtForward: '' as any,
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries || '',
        vegetables: initialData.vegetables || '',
        fishEgg: initialData.fishEgg || '',
        chicken: initialData.chicken || '',
        houseRent: initialData.houseRent || '',
        dailyCash: initialData.dailyCash || '',
        broughtForward: initialData.broughtForward || '',
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? (value === '' ? '' : parseFloat(value)) : value
    }));
  };

  const val = (v: any) => parseFloat(v) || 0;

  const totalExpenses = 
    val(formData.groceries) + 
    val(formData.vegetables) + 
    val(formData.fishEgg) + 
    val(formData.chicken) + 
    val(formData.houseRent);

  const totalBalance = val(formData.broughtForward) + val(formData.dailyCash) - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('default', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      groceries: val(formData.groceries),
      vegetables: val(formData.vegetables),
      fishEgg: val(formData.fishEgg),
      chicken: val(formData.chicken),
      houseRent: val(formData.houseRent),
      dailyCash: val(formData.dailyCash),
      broughtForward: val(formData.broughtForward),
      month: monthName,
      totalExpenses,
      totalBalance,
      timestamp: new Date().toISOString()
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.date}</label>
          <input
            type="date"
            name="date"
            required
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.date}
            onChange={handleChange}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.broughtForward}</label>
          <input
            type="number"
            name="broughtForward"
            placeholder="0"
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.broughtForward}
            onChange={handleChange}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {[
          { name: 'dailyCash', label: t.dailyCash, highlight: true },
          { name: 'groceries', label: t.groceries },
          { name: 'vegetables', label: t.vegetables },
          { name: 'fishEgg', label: t.fishEgg },
          { name: 'chicken', label: t.chicken },
          { name: 'houseRent', label: t.houseRent },
        ].map(field => (
          <div key={field.name}>
            <label className={`block text-sm font-semibold mb-1 ${field.highlight ? 'text-indigo-700' : 'text-slate-700'}`}>{field.label}</label>
            <input
              type="number"
              name={field.name}
              placeholder="0"
              className={`w-full px-4 py-2.5 rounded-xl border transition-all focus:ring-2 focus:ring-indigo-500 outline-none ${field.highlight ? 'border-indigo-200 bg-indigo-50 font-bold' : 'border-slate-200'}`}
              value={(formData as any)[field.name]}
              onChange={handleChange}
            />
          </div>
        ))}
      </div>

      <div className="p-6 bg-slate-50 rounded-2xl flex flex-wrap gap-8 items-center justify-center border border-slate-100">
        <div className="text-center">
          <p className="text-xs text-slate-400 uppercase tracking-wider font-bold">{t.totalExpenses}</p>
          <p className="text-2xl font-black text-rose-600">LKR {totalExpenses.toLocaleString()}</p>
        </div>
        <div className="text-center">
          <p className="text-xs text-slate-400 uppercase tracking-wider font-bold">{t.totalBalance}</p>
          <p className="text-2xl font-black text-emerald-600">LKR {totalBalance.toLocaleString()}</p>
        </div>
      </div>

      <button
        type="submit"
        className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-[0.99] transition-all"
      >
        {t.save}
      </button>
    </form>
  );
};

export default TransactionForm;

import React from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, Download } from 'lucide-react';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, onEdit, onDelete, isLoading }) => {
  const exportToCsv = () => {
    if (transactions.length === 0) return;

    const headers = ["Date", "Month", "Groceries", "Vegetables", "FishEgg", "Chicken", "HouseRent", "DailyCash", "BroughtForward", "TotalExp", "TotalBalance", "Timestamp"];
    const rows = transactions.map(tx => [
      tx.date, tx.month, tx.groceries, tx.vegetables, tx.fishEgg, tx.chicken, tx.houseRent, tx.dailyCash, tx.broughtForward, tx.totalExpenses, tx.totalBalance, tx.timestamp
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `finance_report_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  if (isLoading) {
    return <div className="p-12 text-center text-slate-400">Loading records...</div>;
  }

  if (transactions.length === 0) {
    return (
      <div className="p-12 text-center">
        <p className="text-slate-400 mb-4">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col">
      <div className="p-4 border-b border-slate-50 flex justify-end">
        <button 
          onClick={exportToCsv}
          className="flex items-center gap-2 text-indigo-600 font-bold text-sm hover:bg-indigo-50 px-4 py-2 rounded-xl transition-all"
        >
          <Download className="w-4 h-4" />
          {t.exportCsv}
        </button>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[1000px]">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase tracking-wider font-black">
              <th className="px-6 py-4">{t.date}</th>
              <th className="px-6 py-4">{t.dailyCash}</th>
              <th className="px-6 py-4">{t.totalExpenses}</th>
              <th className="px-6 py-4">{t.totalBalance}</th>
              <th className="px-6 py-4 text-slate-400 text-center">Breakdown (G/V/F/C/H)</th>
              <th className="px-6 py-4 text-center">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.slice().reverse().map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 text-sm font-bold text-emerald-600">LKR {tx.dailyCash?.toLocaleString()}</td>
                <td className="px-6 py-4 text-sm font-bold text-rose-500">LKR {tx.totalExpenses?.toLocaleString()}</td>
                <td className="px-6 py-4 text-sm font-black text-slate-900">LKR {tx.totalBalance?.toLocaleString()}</td>
                <td className="px-6 py-4 text-[10px] text-slate-400 font-medium text-center">
                   {tx.groceries} / {tx.vegetables} / {tx.fishEgg} / {tx.chicken} / {tx.houseRent}
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center justify-center gap-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => (tx.id || tx.timestamp) && onDelete(tx.id || tx.timestamp!)}
                      className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useMemo } from 'react';
import { Transaction } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  PieChart, Pie, Cell 
} from 'recharts';

interface MonthlyChartsProps {
  t: any;
  transactions: Transaction[];
}

const COLORS = ['#4f46e5', '#10b981', '#f43f5e', '#f59e0b', '#8b5cf6'];

const MonthlyCharts: React.FC<MonthlyChartsProps> = ({ t, transactions }) => {
  const categoryData = useMemo(() => {
    const data = [
      { name: t.groceries, value: 0 },
      { name: t.vegetables, value: 0 },
      { name: t.fishEgg, value: 0 },
      { name: t.chicken, value: 0 },
      { name: t.houseRent, value: 0 },
    ];

    transactions.forEach(tx => {
      data[0].value += tx.groceries;
      data[1].value += tx.vegetables;
      data[2].value += tx.fishEgg;
      data[3].value += tx.chicken;
      data[4].value += tx.houseRent;
    });

    return data.filter(d => d.value > 0);
  }, [transactions, t]);

  if (transactions.length === 0) {
    return (
      <div className="bg-white p-12 rounded-3xl border border-slate-100 text-center">
        <p className="text-slate-400">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
      <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
        <h3 className="font-bold text-slate-700 mb-6">{t.expensesByCategory}</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={categoryData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
              <YAxis fontSize={12} tickLine={false} axisLine={false} />
              <Tooltip 
                cursor={{fill: '#f8fafc'}}
                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
              />
              <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
        <h3 className="font-bold text-slate-700 mb-6">{t.expenseDistribution}</h3>
        <div className="h-[300px] flex flex-col items-center">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={categoryData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={100}
                paddingAngle={5}
                dataKey="value"
              >
                {categoryData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
              <Legend layout="horizontal" align="center" verticalAlign="bottom" />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

export default MonthlyCharts;

