import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';

interface TransactionFormProps {
  t: any;
  initialData?: Transaction | null;
  onSubmit: (data: Transaction) => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, initialData, onSubmit }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: '' as any,
    vegetables: '' as any,
    fishEgg: '' as any,
    chicken: '' as any,
    houseRent: '' as any,
    travel: '' as any,
    others: '' as any,
    dailyCash: '' as any,
    broughtForward: '' as any,
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries || '',
        vegetables: initialData.vegetables || '',
        fishEgg: initialData.fishEgg || '',
        chicken: initialData.chicken || '',
        houseRent: initialData.houseRent || '',
        travel: initialData.travel || '',
        others: initialData.others || '',
        dailyCash: initialData.dailyCash || '',
        broughtForward: initialData.broughtForward || '',
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? (value === '' ? '' : parseFloat(value)) : value
    }));
  };

  const val = (v: any) => parseFloat(v) || 0;

  const totalExpenses = 
    val(formData.groceries) + 
    val(formData.vegetables) + 
    val(formData.fishEgg) + 
    val(formData.chicken) + 
    val(formData.houseRent) +
    val(formData.travel) +
    val(formData.others);

  const totalBalance = val(formData.broughtForward) + val(formData.dailyCash) - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('default', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      groceries: val(formData.groceries),
      vegetables: val(formData.vegetables),
      fishEgg: val(formData.fishEgg),
      chicken: val(formData.chicken),
      houseRent: val(formData.houseRent),
      travel: val(formData.travel),
      others: val(formData.others),
      dailyCash: val(formData.dailyCash),
      broughtForward: val(formData.broughtForward),
      month: monthName,
      totalExpenses,
      totalBalance,
      timestamp: new Date().toISOString()
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.date}</label>
          <input
            type="date"
            name="date"
            required
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.date}
            onChange={handleChange}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.broughtForward}</label>
          <input
            type="number"
            name="broughtForward"
            placeholder="0"
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.broughtForward}
            onChange={handleChange}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {[
          { name: 'dailyCash', label: t.dailyCash, highlight: true },
          { name: 'groceries', label: t.groceries },
          { name: 'vegetables', label: t.vegetables },
          { name: 'fishEgg', label: t.fishEgg },
          { name: 'chicken', label: t.chicken },
          { name: 'houseRent', label: t.houseRent },
          { name: 'travel', label: t.travel },
          { name: 'others', label: t.others },
        ].map(field => (
          <div key={field.name}>
            <label className={`block text-sm font-semibold mb-1 ${field.highlight ? 'text-indigo-700' : 'text-slate-700'}`}>{field.label}</label>
            <input
              type="number"
              name={field.name}
              placeholder="0"
              className={`w-full px-4 py-2.5 rounded-xl border transition-all focus:ring-2 focus:ring-indigo-500 outline-none ${field.highlight ? 'border-indigo-200 bg-indigo-50 font-bold' : 'border-slate-200'}`}
              value={(formData as any)[field.name]}
              onChange={handleChange}
            />
          </div>
        ))}
      </div>

      <div className="p-6 bg-slate-50 rounded-2xl flex flex-wrap gap-8 items-center justify-center border border-slate-100">
        <div className="text-center">
          <p className="text-xs text-slate-400 uppercase tracking-wider font-bold">{t.totalExpenses}</p>
          <p className="text-2xl font-black text-rose-600">LKR {totalExpenses.toLocaleString()}</p>
        </div>
        <div className="text-center">
          <p className="text-xs text-slate-400 uppercase tracking-wider font-bold">{t.totalBalance}</p>
          <p className="text-2xl font-black text-emerald-600">LKR {totalBalance.toLocaleString()}</p>
        </div>
      </div>

      <button
        type="submit"
        className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-[0.99] transition-all"
      >
        {t.save}
      </button>
    </form>
  );
};

