const SHEET_NAME = 'Transactions';

function setup() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_NAME);
    sheet.appendRow([
      'ID', 'Date', 'Month', 'Groceries', 'Vegetables', 
      'FishEgg', 'Chicken', 'HouseRent', 'Travel', 'Others',
      'DailyCash', 'BroughtForward', 'TotalExpenses', 'TotalBalance', 'Timestamp'
    ]);
  }
}

function doPost(e) {
  const data = JSON.parse(e.postData.contents);
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);
  const action = data.action;

  if (action === 'create') {
    const id = Utilities.getUuid();
    sheet.appendRow([
      id, data.date, data.month, data.groceries, data.vegetables,
      data.fishEgg, data.chicken, data.houseRent, data.travel, data.others,
      data.dailyCash, data.broughtForward, data.totalExpenses, data.totalBalance, data.timestamp
    ]);
    return ContentService.createTextOutput(JSON.stringify({ status: 'success', id })).setMimeType(ContentService.MimeType.JSON);
  }

  if (action === 'update') {
    const values = sheet.getDataRange().getValues();
    for (let i = 1; i < values.length; i++) {
      if (values[i][0] == data.id) {
        sheet.getRange(i + 1, 1, 1, 15).setValues([[
          data.id, data.date, data.month, data.groceries, data.vegetables,
          data.fishEgg, data.chicken, data.houseRent, data.travel, data.others,
          data.dailyCash, data.broughtForward, data.totalExpenses, data.totalBalance, data.timestamp
        ]]);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
  }

  if (action === 'delete') {
    const values = sheet.getDataRange().getValues();
    for (let i = 1; i < values.length; i++) {
      if (values[i][0] == data.id) {
        sheet.deleteRow(i + 1);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doGet(e) {
  const action = e.parameter.action;
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);

  if (!sheet) {
    setup();
    return ContentService.createTextOutput(JSON.stringify({ records: [] })).setMimeType(ContentService.MimeType.JSON);
  }

  const values = sheet.getDataRange().getValues();
  if (values.length <= 1) {
    return ContentService.createTextOutput(JSON.stringify({ records: [] })).setMimeType(ContentService.MimeType.JSON);
  }

  const headers = values[0];
  const records = [];

  for (let i = 1; i < values.length; i++) {
    const record = {};
    headers.forEach((header, index) => {
      let key = header.charAt(0).toLowerCase() + header.slice(1);
      // Clean up key name if it has spaces (e.g. "House Rent" -> "houseRent")
      key = key.replace(/\s+/g, '');
      record[key] = values[i][index];
    });
    records.push(record);
  }

  return ContentService.createTextOutput(JSON.stringify({ records })).setMimeType(ContentService.MimeType.JSON);
}

import React, { useState, useEffect } from 'react';
import { Transaction, Language } from './types';
import { translations } from './translations';
import { googleSheetsService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, RefreshCw } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);
  const [lastSynced, setLastSynced] = useState<Date | null>(null);

  const t = translations[lang];

  useEffect(() => {
    loadData();
    const savedLang = localStorage.getItem('lang');
    if (savedLang) setLang(savedLang as Language);
  }, []);

  const loadData = async () => {
    setIsLoading(true);
    const data = await googleSheetsService.fetchTransactions();
    setTransactions(data);
    setLastSynced(new Date());
    setIsLoading(false);
  };

  const toggleLanguage = () => {
    const newLang = lang === 'en' ? 'si' : 'en';
    setLang(newLang);
    localStorage.setItem('lang', newLang);
  };

  const onAddTransaction = async (data: Transaction) => {
    setIsLoading(true);
    const success = await googleSheetsService.addTransaction(data);
    if (success) {
      // Small delay to allow Google Script to process before refetching
      setTimeout(() => loadData(), 1000);
    } else {
      setIsLoading(false);
    }
  };

  const onUpdateTransaction = async (id: string, data: Transaction) => {
    setIsLoading(true);
    const success = await googleSheetsService.updateTransaction(id, data);
    if (success) {
      setTimeout(() => loadData(), 1000);
    } else {
      setIsLoading(false);
    }
  };

  const onDeleteTransaction = async (id: string) => {
    if(confirm(t.confirmDelete)) {
      setIsLoading(true);
      const success = await googleSheetsService.deleteTransaction(id);
      if (success) {
        setTimeout(() => loadData(), 1000);
      } else {
        setIsLoading(false);
      }
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0">
      {/* Sidebar / Desktop Nav */}
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white border-r border-slate-200 p-6 z-20">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'dashboard' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            {t.dashboard}
          </button>
          <button 
            onClick={() => setActiveTab('analytics')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'analytics' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <BarChart3 className="w-5 h-5" />
            {t.charts}
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'history' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <History className="w-5 h-5" />
            {t.history}
          </button>
        </div>

        <div className="mt-auto pt-6 border-t border-slate-100">
          <div className="px-4 py-2 mb-4">
            <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Status</p>
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isLoading ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`} />
              <p className="text-xs font-medium text-slate-600">
                {isLoading ? 'Syncing...' : 'Connected'}
