const SHEET_NAME = 'Transactions';

function setup() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_NAME);
    sheet.appendRow([
      'ID', 'Date', 'Month', 'Groceries', 'Vegetables', 
      'FishEgg', 'Chicken', 'HouseRent', 'Travel', 'Others',
      'DailyCash', 'BroughtForward', 'TotalExpenses', 'TotalBalance', 'Timestamp'
    ]);
  }
}

function doPost(e) {
  let data;
  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ status: 'error', message: 'Invalid JSON' })).setMimeType(ContentService.MimeType.JSON);
  }

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);
  const action = data.action;

  if (action === 'create') {
    const id = Utilities.getUuid();
    sheet.appendRow([
      id, data.date, data.month, data.groceries, data.vegetables,
      data.fishEgg, data.chicken, data.houseRent, data.travel, data.others,
      data.dailyCash, data.broughtForward, data.totalExpenses, data.totalBalance, data.timestamp
    ]);
    return ContentService.createTextOutput(JSON.stringify({ status: 'success', id })).setMimeType(ContentService.MimeType.JSON);
  }

  if (action === 'update') {
    const values = sheet.getDataRange().getValues();
    for (let i = 1; i < values.length; i++) {
      if (values[i][0] == data.id) {
        sheet.getRange(i + 1, 1, 1, 15).setValues([[
          data.id, data.date, data.month, data.groceries, data.vegetables,
          data.fishEgg, data.chicken, data.houseRent, data.travel, data.others,
          data.dailyCash, data.broughtForward, data.totalExpenses, data.totalBalance, data.timestamp
        ]]);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
  }

  if (action === 'delete') {
    const values = sheet.getDataRange().getValues();
    for (let i = 1; i < values.length; i++) {
      if (values[i][0] == data.id) {
        sheet.deleteRow(i + 1);
        break;
      }
    }
    return ContentService.createTextOutput(JSON.stringify({ status: 'success' })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);

  if (!sheet) {
    setup();
    sheet = ss.getSheetByName(SHEET_NAME);
  }

  const values = sheet.getDataRange().getValues();
  if (values.length <= 1) {
    return ContentService.createTextOutput(JSON.stringify({ records: [] }))
      .setMimeType(ContentService.MimeType.JSON);
  }

  const headers = values[0];
  const records = [];

  // Explicit mapping to ensure JS object keys match Transaction interface
  const keyMap = {
    'ID': 'id',
    'Date': 'date',
    'Month': 'month',
    'Groceries': 'groceries',
    'Vegetables': 'vegetables',
    'FishEgg': 'fishEgg',
    'Chicken': 'chicken',
    'HouseRent': 'houseRent',
    'Travel': 'travel',
    'Others': 'others',
    'DailyCash': 'dailyCash',
    'BroughtForward': 'broughtForward',
    'TotalExpenses': 'totalExpenses',
    'TotalBalance': 'totalBalance',
    'Timestamp': 'timestamp'
  };

  for (let i = 1; i < values.length; i++) {
    const record = {};
    headers.forEach((header, index) => {
      const key = keyMap[header] || header.toLowerCase().replace(/\s+/g, '');
      let val = values[i][index];

      // Format Dates properly for the frontend <input type="date">
      if (header === 'Date' && val instanceof Date) {
        val = Utilities.formatDate(val, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
      }

      record[key] = val;
    });
    records.push(record);
  }

  const output = JSON.stringify({ records: records });
  return ContentService.createTextOutput(output)
    .setMimeType(ContentService.MimeType.JSON);
}

