// IMPORTANT: Ensure this URL matches your deployed "Anyone" web app URL from Google Apps Script
const API_URL = 'https://script.google.com/macros/s/AKfycbw8Qo64ZJZuAptrshwpRmvCiv0Vw3Vv9ks4HR8XDU-kBNc_di3KDm0UR5ftdDTwGcVl/exec';

const getMockData = (): Transaction[] => {
  const data = localStorage.getItem('transactions_data_v2');
  return data ? JSON.parse(data) : [];
};

const saveMockData = (data: Transaction[]) => {
  localStorage.setItem('transactions_data_v2', JSON.stringify(data));
};

export const googleSheetsService = {
  async fetchTransactions(): Promise<Transaction[]> {
    try {
      const cacheBuster = `_t=${Date.now()}`;
      const url = API_URL.includes('?') ? `${API_URL}&action=read&${cacheBuster}` : `${API_URL}?action=read&${cacheBuster}`;

      console.log("Fetching from:", url);
      const response = await fetch(url);

      if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

      const data = await response.json();
      console.log("Data received from sheet:", data);

      if (data && data.records) {
        saveMockData(data.records);
        return data.records;
      }
      return [];
    } catch (error) {
      console.error("Critical error fetching from Google Sheets:", error);
      const local = getMockData();
      console.log("Falling back to local data:", local);
      return local;
    }
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    try {
      const payload = {
        action: 'create',
        ...transaction,
        timestamp: new Date().toISOString()
      };

      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      return true;
    } catch (error) {
      console.error("Failed to add transaction", error);
      return false;
    }
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    try {
      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'update', id, ...transaction }),
      });
      return true;
    } catch (error) {
      console.error("Failed to update transaction", error);
      return false;
    }
  },

  async deleteTransaction(id: string): Promise<boolean> {
    try {
      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'delete', id }),
      });
      return true;
    } catch (error) {
      console.error("Failed to delete transaction", error);
      return false;
    }
  },

  async login(email: string, password: string): Promise<User | null> {
    try {
      const users = JSON.parse(localStorage.getItem('app_users_v2') || '[]');
      const user = users.find((u: any) => u.email === email && u.password === password);
      if (user) {
        const { password: _, ...userWithoutPassword } = user;
        return userWithoutPassword;
      }
      return null;
    } catch (error) {
      return null;
    }
  },

  async register(name: string, email: string, password: string): Promise<User | null> {
    try {
      const users = JSON.parse(localStorage.getItem('app_users_v2') || '[]');
      if (users.find((u: any) => u.email === email)) return null;
      const newUser = { id: Date.now().toString(), name, email, password };
      users.push(newUser);
      localStorage.setItem('app_users_v2', JSON.stringify(users));
      const { password: _, ...userWithoutPassword } = newUser;
      return userWithoutPassword;
    } catch (error) {
      return null;
    }
  }
};

