  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  isLoading 
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('default', { month: 'long', year: 'numeric' });
  }, []);

  const [selectedMonth, setSelectedMonth] = useState<string>(currentMonthName);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  // If selectedMonth is empty or has no data, try to pick the latest month with data
  useEffect(() => {
    const monthsWithData = transactions.map(tx => tx.month?.trim());
    if (transactions.length > 0 && !monthsWithData.includes(selectedMonth)) {
      setSelectedMonth(monthsWithData[monthsWithData.length - 1] || currentMonthName);
    }
  }, [transactions, currentMonthName]);

  const monthlySummary: MonthlySummary[] = useMemo(() => {
    const summaryMap: Record<string, MonthlySummary> = {};

    transactions.forEach((tx) => {
      const monthKey = tx.month?.trim() || 'Unknown';
      if (!summaryMap[monthKey]) {
        summaryMap[monthKey] = {
          month: monthKey,
          totalGroceries: 0,
          totalVegetables: 0,
          totalFishEgg: 0,
          totalChicken: 0,
          totalHouseRent: 0,
          totalTravel: 0,
          totalOthers: 0,
          totalExpenses: 0,
          totalDailyCash: 0,
          broughtForward: Number(tx.broughtForward) || 0,
          totalBalance: 0
        };
      }
      summaryMap[monthKey].totalGroceries += (Number(tx.groceries) || 0);
      summaryMap[monthKey].totalVegetables += (Number(tx.vegetables) || 0);
      summaryMap[monthKey].totalFishEgg += (Number(tx.fishEgg) || 0);
      summaryMap[monthKey].totalChicken += (Number(tx.chicken) || 0);
      summaryMap[monthKey].totalHouseRent += (Number(tx.houseRent) || 0);
      summaryMap[monthKey].totalTravel += (Number(tx.travel) || 0);
      summaryMap[monthKey].totalOthers += (Number(tx.others) || 0);
      summaryMap[monthKey].totalExpenses += (Number(tx.totalExpenses) || 0);
      summaryMap[monthKey].totalDailyCash += (Number(tx.dailyCash) || 0);
      summaryMap[monthKey].totalBalance = (Number(tx.totalBalance) || 0); 
    });

    return Object.values(summaryMap).sort((a, b) => {
      const dateA = new Date(a.month);
      const dateB = new Date(b.month);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions]);

  const filteredStats = useMemo(() => {
    const monthTx = transactions.filter(tx => tx.month?.trim() === selectedMonth);
    const totalSpent = monthTx.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const totalReceived = monthTx.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const lastBalance = monthTx.length > 0 ? (Number(monthTx[monthTx.length - 1].totalBalance) || 0) : 0;

    return { totalSpent, totalReceived, lastBalance };
  }, [transactions, selectedMonth]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleCloseForm = () => {
    setShowAddForm(false);
    setEditingTransaction(null);
  };

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month?.trim() === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const recentTransactions = useMemo(() => {
    return transactions.slice().reverse().slice(0, 5);
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-3xl border border-slate-100 shadow-sm">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 outline-none cursor-pointer hover:text-indigo-600 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m}>{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <button 
            onClick={() => window.location.reload()}
            className={`p-3 bg-slate-50 text-slate-400 rounded-2xl hover:text-indigo-600 transition-all ${isLoading ? 'animate-spin' : ''}`}
            title="Refresh from Sheet"
          >
            <RefreshCw className="w-5 h-5" />
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-grow sm:flex-grow-0 bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            {t.addRecord}
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          <StatsOverview t={t} stats={filteredStats} />

          <div className="mt-8 bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <ClipboardList className="w-6 h-6 text-indigo-600" />
                <h2 className="text-xl font-bold text-slate-800">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-sm font-bold text-indigo-600 hover:text-indigo-700 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[800px]">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.dailyCash}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 text-indigo-700">{t.totalBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {recentTransactions.map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600">LKR {Number(tx.dailyCash)?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500">LKR {Number(tx.totalExpenses)?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 bg-indigo-50/20">LKR {Number(tx.totalBalance)?.toLocaleString()}</td>
                    </tr>
                  ))}
                  {recentTransactions.length === 0 && (
                    <tr>
                      <td colSpan={4} className="px-6 py-12 text-center text-slate-400 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>

          <div className="mt-8">
            <h2 className="text-xl font-bold text-slate-800 mb-4">{t.summary}</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {monthlySummary.map((sum) => (
                  <div 
                    key={sum.month} 
                    onClick={() => setSelectedMonth(sum.month)}
                    className={`bg-white p-6 rounded-3xl shadow-sm border transition-all cursor-pointer ${selectedMonth === sum.month ? 'border-indigo-500 ring-2 ring-indigo-50' : 'border-slate-100 hover:shadow-md'}`}
                  >
                    <div className="flex justify-between items-center mb-4">
                       <h3 className="font-bold text-lg text-indigo-600">{sum.month}</h3>
                       {sum.month === currentMonthName && (
                         <span className="bg-emerald-50 text-emerald-700 text-[10px] font-black px-2 py-0.5 rounded-full uppercase">Current</span>
                       )}
                    </div>
                    <div className="space-y-2">
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.totalExpenses}</span>
                         <span className="font-semibold text-rose-500">LKR {sum.totalExpenses.toLocaleString()}</span>
                       </div>
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.dailyCash}</span>
                         <span className="font-semibold text-emerald-600">LKR {sum.totalDailyCash.toLocaleString()}</span>
                       </div>
                       <div className="pt-2 border-t border-slate-50 flex justify-between">
                         <span className="font-bold text-slate-700">{t.totalBalance}</span>
                         <span className="font-bold text-slate-900">LKR {sum.totalBalance.toLocaleString()}</span>
                       </div>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center gap-3 mb-6">
              <div className="p-2 bg-indigo-100 rounded-xl">
                <BarChart3 className="w-6 h-6 text-indigo-700" />
              </div>
              <h2 className="text-2xl font-black text-slate-800">{t.charts} - {selectedMonth}</h2>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800">{t.history} ({selectedMonth})</h2>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions.filter(tx => tx.month?.trim() === selectedMonth)} 
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col scale-in-center">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={handleCloseForm}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  handleCloseForm();
                }} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import { Transaction, User } from '../types';

const API_URL = 'https://script.google.com/macros/s/AKfycbw8Qo64ZJZuAptrshwpRmvCiv0Vw3Vv9ks4HR8XDU-kBNc_di3KDm0UR5ftdDTwGcVl/exec';

const getMockData = (): Transaction[] => {
  const data = localStorage.getItem('transactions_data_v2');
  return data ? JSON.parse(data) : [];
};

const saveMockData = (data: Transaction[]) => {
  localStorage.setItem('transactions_data_v2', JSON.stringify(data));
};

export const googleSheetsService = {
  // Fix: Added missing login method to handle user authentication
  async login(email: string, password: string): Promise<User | null> {
    try {
      const url = `${API_URL}${API_URL.includes('?') ? '&' : '?'}action=login&email=${encodeURIComponent(email)}&password=${encodeURIComponent(password)}`;
      const response = await fetch(url);
      if (!response.ok) return null;
      const data = await response.json();
      return data.success ? data.user : null;
    } catch (error) {
      console.error("Login failed", error);
      return null;
    }
  },

  // Fix: Added missing register method to handle new user registration
  async register(name: string, email: string, password: string): Promise<User | null> {
    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'register', name, email, password }),
      });
      // We attempt to read the JSON response to extract user details
      const data = await response.json();
      return data.success ? data.user : null;
    } catch (error) {
      console.error("Registration failed", error);
      return null;
    }
  },

  async fetchTransactions(): Promise<Transaction[]> {
    try {
      const cacheBuster = `_t=${Date.now()}`;
      const url = `${API_URL}${API_URL.includes('?') ? '&' : '?'}action=read&${cacheBuster}`;

      const response = await fetch(url, {
        method: 'GET',
        headers: { 'Accept': 'application/json' }
      });

      if (!response.ok) throw new Error(`Fetch failed: ${response.status}`);

      const data = await response.json();

      if (data && Array.isArray(data.records)) {
        // Basic data validation
        const cleanedRecords = data.records.map((r: any) => ({
          ...r,
          month: r.month ? String(r.month).trim() : 'Unknown',
          date: r.date ? String(r.date).trim() : '',
          totalExpenses: Number(r.totalExpenses) || 0,
          totalBalance: Number(r.totalBalance) || 0,
          dailyCash: Number(r.dailyCash) || 0
        }));

        saveMockData(cleanedRecords);
        return cleanedRecords;
      }
      return [];
    } catch (error) {
      console.error("Critical error fetching from Google Sheets:", error);
      return getMockData();
    }
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    try {
      const payload = {
        action: 'create',
        ...transaction,
        timestamp: new Date().toISOString()
      };

      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      return true;
    } catch (error) {
      console.error("Failed to add transaction", error);
      return false;
    }
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    try {
      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'update', id, ...transaction }),
      });
      return true;
    } catch (error) {
      console.error("Failed to update transaction", error);
      return false;
    }
  },

  async deleteTransaction(id: string): Promise<boolean> {
    try {
      await fetch(API_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'delete', id }),
      });
      return true;
    } catch (error) {
      console.error("Failed to delete transaction", error);
      return false;
    }
  }
};

import React from 'react';
import { Transaction } from '../types';
import { Edit2, Trash2, FileSpreadsheet, Download } from 'lucide-react';
import * as XLSX from 'xlsx';

interface HistoryTableProps {
  t: any;
  transactions: Transaction[];
  allTransactions?: Transaction[]; // Full data for global export
  onEdit: (tx: Transaction) => void;
  onDelete: (id: string) => void;
  isLoading: boolean;
}

const HistoryTable: React.FC<HistoryTableProps> = ({ t, transactions, allTransactions, onEdit, onDelete, isLoading }) => {
  const exportToExcel = (dataToExport: Transaction[], fileName: string) => {
    if (dataToExport.length === 0) return;

    // Format data with user-friendly headers from translations
    const worksheetData = dataToExport.map(tx => ({
      [t.date]: tx.date,
      [t.month]: tx.month,
      [t.groceries]: tx.groceries,
      [t.vegetables]: tx.vegetables,
      [t.fishEgg]: tx.fishEgg,
      [t.chicken]: tx.chicken,
      [t.houseRent]: tx.houseRent,
      [t.travel]: tx.travel,
      [t.others]: tx.others,
      [t.dailyCash]: tx.dailyCash,
      [t.broughtForward]: tx.broughtForward,
      [t.totalExpenses]: tx.totalExpenses,
      [t.totalBalance]: tx.totalBalance,
      "Timestamp": tx.timestamp
    }));

    const worksheet = XLSX.utils.json_to_sheet(worksheetData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Transactions");

    // Download the .xlsx file
    XLSX.writeFile(workbook, `${fileName}.xlsx`);
  };

  const exportToCSV = (dataToExport: Transaction[], fileName: string) => {
    if (dataToExport.length === 0) return;

    // Define headers
    const headers = [
      t.date, t.month, t.groceries, t.vegetables, t.fishEgg, t.chicken, 
      t.houseRent, t.travel, t.others, t.dailyCash, t.broughtForward, 
      t.totalExpenses, t.totalBalance, "Timestamp"
    ];

    // Create rows
    const rows = dataToExport.map(tx => [
      tx.date,
      tx.month,
      tx.groceries,
      tx.vegetables,
      tx.fishEgg,
      tx.chicken,
      tx.houseRent,
      tx.travel,
      tx.others,
      tx.dailyCash,
      tx.broughtForward,
      tx.totalExpenses,
      tx.totalBalance,
      tx.timestamp
    ]);

    // Construct CSV content
    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.map(value => `"${value}"`).join(','))
    ].join('\n');

    // Create Blob and Download
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    if (link.download !== undefined) {
      const url = URL.createObjectURL(blob);
      link.setAttribute('href', url);
      link.setAttribute('download', `${fileName}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  if (isLoading) {
    return <div className="p-12 text-center text-slate-400">Loading records...</div>;
  }

  if (transactions.length === 0) {
    return (
      <div className="p-12 text-center">
        <p className="text-slate-400 mb-4">{t.noData}</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col">
      <div className="p-4 border-b border-slate-50 flex justify-end gap-2 flex-wrap">
        <button 
          onClick={() => exportToCSV(transactions, `finance_report_${transactions[0]?.month || 'monthly'}`)}
          className="flex items-center gap-2 text-slate-600 font-bold text-sm hover:bg-slate-100 px-4 py-2 rounded-xl transition-colors"
        >
          <Download className="w-4 h-4" />
          {t.exportCsv}
        </button>
        <button 
          onClick={() => exportToExcel(transactions, `finance_report_${transactions[0]?.month || 'monthly'}`)}
          className="flex items-center gap-2 text-indigo-600 font-bold text-sm hover:bg-indigo-50 px-4 py-2 rounded-xl transition-colors"
        >
          <FileSpreadsheet className="w-4 h-4" />
          {t.exportExcel}
        </button>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left min-w-[1000px]">
          <thead>
            <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-100">
              <th className="px-6 py-4">{t.date}</th>
              <th className="px-6 py-4">{t.dailyCash}</th>
              <th className="px-6 py-4">{t.groceries}</th>
              <th className="px-6 py-4">{t.vegetables}</th>
              <th className="px-6 py-4">{t.fishEgg}</th>
              <th className="px-6 py-4">{t.chicken}</th>
              <th className="px-6 py-4">{t.houseRent}</th>
              <th className="px-6 py-4">{t.travel}</th>
              <th className="px-6 py-4">{t.others}</th>
              <th className="px-6 py-4">{t.totalExpenses}</th>
              <th className="px-6 py-4 bg-indigo-50/30 text-indigo-700">{t.totalBalance}</th>
              <th className="px-6 py-4 text-center">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 text-sm">
            {transactions.map((tx) => (
              <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                <td className="px-6 py-4 font-bold text-emerald-600">LKR {tx.dailyCash?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.groceries?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.vegetables?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.fishEgg?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.chicken?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.houseRent?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.travel?.toLocaleString()}</td>
                <td className="px-6 py-4 text-slate-600">{tx.others?.toLocaleString()}</td>
                <td className="px-6 py-4 font-bold text-rose-500">LKR {tx.totalExpenses?.toLocaleString()}</td>
                <td className="px-6 py-4 font-black text-indigo-600 bg-indigo-50/20">LKR {tx.totalBalance?.toLocaleString()}</td>
                <td className="px-6 py-4">
                  <div className="flex items-center justify-center gap-2">
                    <button 
                      onClick={() => onEdit(tx)}
                      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                    >
                      <Edit2 className="w-4 h-4" />
                    </button>
                    <button 
                      onClick={() => tx.id && onDelete(tx.id)}
                      className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default HistoryTable;

import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, Language } from './types';
import { translations } from './translations';
import { googleSheetsService } from './services/googleSheets';
import Dashboard from './components/Dashboard';
import { Globe, Wallet, LayoutDashboard, History, BarChart3, RefreshCw } from 'lucide-react';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('en');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'analytics' | 'history'>('dashboard');
  const [isLoading, setIsLoading] = useState(false);
  const [lastSynced, setLastSynced] = useState<Date | null>(null);

  const t = translations[lang];

  const loadData = useCallback(async (showLoading = true) => {
    if (showLoading) setIsLoading(true);
    const data = await googleSheetsService.fetchTransactions();
    setTransactions(data);
    setLastSynced(new Date());
    if (showLoading) setIsLoading(false);
  }, []);

  useEffect(() => {
    loadData();
    const savedLang = localStorage.getItem('lang');
    if (savedLang) setLang(savedLang as Language);

    // Auto-update every 60 seconds
    const interval = setInterval(() => {
      loadData(false); 
    }, 60000);

    return () => clearInterval(interval);
  }, [loadData]);

  const toggleLanguage = () => {
    const newLang = lang === 'en' ? 'si' : 'en';
    setLang(newLang);
    localStorage.setItem('lang', newLang);
  };

  const onAddTransaction = async (data: Transaction) => {
    setIsLoading(true);
    const success = await googleSheetsService.addTransaction(data);
    if (success) {
      setTimeout(() => loadData(), 1500);
    } else {
      setIsLoading(false);
    }
  };

  const onUpdateTransaction = async (id: string, data: Transaction) => {
    setIsLoading(true);
    const success = await googleSheetsService.updateTransaction(id, data);
    if (success) {
      setTimeout(() => loadData(), 1500);
    } else {
      setIsLoading(false);
    }
  };

  const onDeleteTransaction = async (id: string) => {
    if(confirm(t.confirmDelete)) {
      setIsLoading(true);
      const success = await googleSheetsService.deleteTransaction(id);
      if (success) {
        setTimeout(() => loadData(), 1500);
      } else {
        setIsLoading(false);
      }
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0 font-sans">
      {/* Sidebar / Desktop Nav */}
      <nav className="hidden md:flex flex-col fixed h-full w-64 bg-white border-r border-slate-200 p-6 z-20">
        <div className="flex items-center gap-3 mb-10">
          <div className="p-2 bg-indigo-600 rounded-xl">
            <Wallet className="w-6 h-6 text-white" />
          </div>
          <h1 className="font-bold text-lg text-slate-800 leading-tight">{t.title}</h1>
        </div>

        <div className="space-y-2 flex-grow">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'dashboard' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <LayoutDashboard className="w-5 h-5" />
            {t.dashboard}
          </button>
          <button 
            onClick={() => setActiveTab('analytics')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'analytics' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <BarChart3 className="w-5 h-5" />
            {t.charts}
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${activeTab === 'history' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
          >
            <History className="w-5 h-5" />
            {t.history}
          </button>
        </div>

        <div className="mt-auto pt-6 border-t border-slate-100">
          <div className="px-4 py-2 mb-4">
            <p className="text-[10px] text-slate-400 font-bold uppercase mb-1">Status</p>
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isLoading ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`} />
              <p className="text-xs font-medium text-slate-600">
                {isLoading ? 'Syncing...' : 'Live Connection'}
              </p>
            </div>
            {lastSynced && (
              <p className="text-[9px] text-slate-400 mt-1">
                Last checked: {lastSynced.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </p>
            )}
          </div>
          <button 
            onClick={toggleLanguage}
            className="w-full flex items-center gap-3 px-4 py-3 text-slate-500 hover:text-indigo-600 font-medium transition-colors"
          >
            <Globe className="w-5 h-5" />
            {t.language}
          </button>
        </div>
      </nav>

      {/* Mobile Top Nav */}
      <header className="md:hidden bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between sticky top-0 z-30">
        <div className="flex items-center gap-2">
          <Wallet className="w-6 h-6 text-indigo-600" />
          <h1 className="font-bold text-sm text-slate-800">{t.title}</h1>
        </div>
        <div className="flex items-center gap-1">
          <button 
            onClick={() => loadData()}
            disabled={isLoading}
            className={`p-2 text-slate-500 hover:bg-slate-100 rounded-lg transition-colors ${isLoading ? 'animate-spin' : ''}`}
          >
            <RefreshCw className="w-5 h-5" />
          </button>
          <button onClick={toggleLanguage} className="p-2 text-slate-500 hover:bg-slate-100 rounded-lg transition-colors">
            <Globe className="w-5 h-5"/>
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="md:pl-64 min-h-screen">
        <div className="max-w-6xl mx-auto p-4 md:p-8">
          <Dashboard 
            activeTab={activeTab} 
            setActiveTab={setActiveTab}
            t={t} 
            transactions={transactions} 
            onAdd={onAddTransaction}
            onUpdate={onUpdateTransaction}
            onDelete={onDeleteTransaction}
            onRefresh={() => loadData()}
            isLoading={isLoading}
          />
        </div>
      </main>

      {/* Mobile Bottom Nav */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex items-center justify-around p-3 z-30 shadow-[0_-4px_12px_rgba(0,0,0,0.05)]">
        <button 
          onClick={() => setActiveTab('dashboard')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'dashboard' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-[10px] font-bold">{t.dashboard}</span>
        </button>
        <button 
          onClick={() => setActiveTab('analytics')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'analytics' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <BarChart3 className="w-6 h-6" />
          <span className="text-[10px] font-bold">{t.charts}</span>
        </button>
        <button 
          onClick={() => setActiveTab('history')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'history' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
          <History className="w-6 h-6" />
          <span className="text-[10px] font-bold">{t.history}</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlySummary } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, RefreshCw } from 'lucide-react';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading 
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('default', { month: 'long', year: 'numeric' });
  }, []);

  const [selectedMonth, setSelectedMonth] = useState<string>(currentMonthName);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  // If selectedMonth is empty or has no data, try to pick the latest month with data
  useEffect(() => {
    const monthsWithData = transactions.map(tx => tx.month?.trim());
    if (transactions.length > 0 && !monthsWithData.includes(selectedMonth)) {
      setSelectedMonth(monthsWithData[monthsWithData.length - 1] || currentMonthName);
    }
  }, [transactions, currentMonthName]);

  const monthlySummary: MonthlySummary[] = useMemo(() => {
    const summaryMap: Record<string, MonthlySummary> = {};

    transactions.forEach((tx) => {
      const monthKey = tx.month?.trim() || 'Unknown';
      if (!summaryMap[monthKey]) {
        summaryMap[monthKey] = {
          month: monthKey,
          totalGroceries: 0,
          totalVegetables: 0,
          totalFishEgg: 0,
          totalChicken: 0,
          totalHouseRent: 0,
          totalTravel: 0,
          totalOthers: 0,
          totalExpenses: 0,
          totalDailyCash: 0,
          broughtForward: Number(tx.broughtForward) || 0,
          totalBalance: 0
        };
      }
      summaryMap[monthKey].totalGroceries += (Number(tx.groceries) || 0);
      summaryMap[monthKey].totalVegetables += (Number(tx.vegetables) || 0);
      summaryMap[monthKey].totalFishEgg += (Number(tx.fishEgg) || 0);
      summaryMap[monthKey].totalChicken += (Number(tx.chicken) || 0);
      summaryMap[monthKey].totalHouseRent += (Number(tx.houseRent) || 0);
      summaryMap[monthKey].totalTravel += (Number(tx.travel) || 0);
      summaryMap[monthKey].totalOthers += (Number(tx.others) || 0);
      summaryMap[monthKey].totalExpenses += (Number(tx.totalExpenses) || 0);
      summaryMap[monthKey].totalDailyCash += (Number(tx.dailyCash) || 0);
      summaryMap[monthKey].totalBalance = (Number(tx.totalBalance) || 0); 
    });

    return Object.values(summaryMap).sort((a, b) => {
      const dateA = new Date(a.month);
      const dateB = new Date(b.month);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions]);

  const filteredStats = useMemo(() => {
    const monthTx = transactions.filter(tx => tx.month?.trim() === selectedMonth);
    const totalSpent = monthTx.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const totalReceived = monthTx.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const lastBalance = monthTx.length > 0 ? (Number(monthTx[monthTx.length - 1].totalBalance) || 0) : 0;

    return { totalSpent, totalReceived, lastBalance };
  }, [transactions, selectedMonth]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleCloseForm = () => {
    setShowAddForm(false);
    setEditingTransaction(null);
  };

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month?.trim() === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const recentTransactions = useMemo(() => {
    return transactions.slice().reverse().slice(0, 5);
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-3xl border border-slate-100 shadow-sm">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 outline-none cursor-pointer hover:text-indigo-600 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m}>{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <button 
            onClick={onRefresh}
            disabled={isLoading}
            className={`flex items-center gap-2 px-6 py-3 bg-slate-50 text-slate-600 rounded-2xl font-bold hover:bg-slate-100 hover:text-indigo-600 transition-all border border-slate-100 ${isLoading ? 'opacity-70 cursor-not-allowed' : 'active:scale-95'}`}
            title={t.refreshData}
          >
            <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            <span className="hidden sm:inline">{t.refreshData}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-grow sm:flex-grow-0 bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            {t.addRecord}
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          <StatsOverview t={t} stats={filteredStats} />

          <div className="mt-8 bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <ClipboardList className="w-6 h-6 text-indigo-600" />
                <h2 className="text-xl font-bold text-slate-800">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-sm font-bold text-indigo-600 hover:text-indigo-700 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[800px]">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.dailyCash}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 text-indigo-700">{t.totalBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {recentTransactions.map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600">LKR {Number(tx.dailyCash)?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500">LKR {Number(tx.totalExpenses)?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 bg-indigo-50/20">LKR {Number(tx.totalBalance)?.toLocaleString()}</td>
                    </tr>
                  ))}
                  {recentTransactions.length === 0 && (
                    <tr>
                      <td colSpan={4} className="px-6 py-12 text-center text-slate-400 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>

          <div className="mt-8">
            <h2 className="text-xl font-bold text-slate-800 mb-4">{t.summary}</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {monthlySummary.map((sum) => (
                  <div 
                    key={sum.month} 
                    onClick={() => setSelectedMonth(sum.month)}
                    className={`bg-white p-6 rounded-3xl shadow-sm border transition-all cursor-pointer ${selectedMonth === sum.month ? 'border-indigo-500 ring-2 ring-indigo-50' : 'border-slate-100 hover:shadow-md'}`}
                  >
                    <div className="flex justify-between items-center mb-4">
                       <h3 className="font-bold text-lg text-indigo-600">{sum.month}</h3>
                       {sum.month === currentMonthName && (
                         <span className="bg-emerald-50 text-emerald-700 text-[10px] font-black px-2 py-0.5 rounded-full uppercase">Current</span>
                       )}
                    </div>
                    <div className="space-y-2">
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.totalExpenses}</span>
                         <span className="font-semibold text-rose-500">LKR {sum.totalExpenses.toLocaleString()}</span>
                       </div>
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.dailyCash}</span>
                         <span className="font-semibold text-emerald-600">LKR {sum.totalDailyCash.toLocaleString()}</span>
                       </div>
                       <div className="pt-2 border-t border-slate-50 flex justify-between">
                         <span className="font-bold text-slate-700">{t.totalBalance}</span>
                         <span className="font-bold text-slate-900">LKR {sum.totalBalance.toLocaleString()}</span>
                       </div>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-100 rounded-xl">
                  <BarChart3 className="w-6 h-6 text-indigo-700" />
                </div>
                <h2 className="text-2xl font-black text-slate-800">{t.charts} - {selectedMonth}</h2>
              </div>
              <button 
                onClick={onRefresh}
                disabled={isLoading}
                className={`flex items-center gap-2 px-5 py-2.5 bg-white text-slate-600 rounded-2xl font-bold hover:text-indigo-600 transition-all border border-slate-100 shadow-sm ${isLoading ? 'opacity-70 cursor-not-allowed' : 'active:scale-95'}`}
              >
                <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
                <span>{t.refreshData}</span>
              </button>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800">{t.history} ({selectedMonth})</h2>
            <button 
              onClick={onRefresh}
              disabled={isLoading}
              className={`flex items-center gap-2 px-4 py-2 bg-slate-50 text-slate-500 rounded-xl text-xs font-bold hover:text-indigo-600 transition-all ${isLoading ? 'opacity-70 cursor-not-allowed' : 'active:scale-95'}`}
            >
              <RefreshCw className={`w-3.5 h-3.5 ${isLoading ? 'animate-spin' : ''}`} />
              <span>{t.refreshData}</span>
            </button>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions.filter(tx => tx.month?.trim() === selectedMonth)} 
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col scale-in-center">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-xl font-bold text-slate-800">
                {editingTransaction ? t.edit : t.addRecord}
              </h3>
              <button 
                onClick={handleCloseForm}
                className="p-2 hover:bg-slate-100 rounded-full transition-colors"
              >
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto">
              <TransactionForm 
                t={t} 
                initialData={editingTransaction}
                onSubmit={(data) => {
                  if (editingTransaction?.id) {
                    onUpdate(editingTransaction.id, data);
                  } else {
                    onAdd(data);
                  }
                  handleCloseForm();
                }} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

/**
 * Personal Finance Tracker - Google Apps Script Backend
 */

const SHEET_NAME = 'Transactions';

function setup() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_NAME);
    sheet.appendRow([
      'ID', 'Date', 'Month', 'Groceries', 'Vegetables', 
      'FishEgg', 'Chicken', 'HouseRent', 'Travel', 'Others',
      'DailyCash', 'BroughtForward', 'TotalExpenses', 'TotalBalance', 'Timestamp'
    ]);
  }
}

// Added OPTIONS handler for CORS preflight
function doOptions(e) {
  return ContentService.createTextOutput("")
    .setMimeType(ContentService.MimeType.TEXT)
    .addHeader("Access-Control-Allow-Origin", "*")
    .addHeader("Access-Control-Allow-Methods", "POST, GET, OPTIONS")
    .addHeader("Access-Control-Allow-Headers", "Content-Type");
}

function doPost(e) {
  let data;
  try {
    data = JSON.parse(e.postData.contents);
  } catch (err) {
    return createJsonResponse({ status: 'error', message: 'Invalid JSON' });
  }

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_NAME);
  const action = data.action;

  if (action === 'create') {
    const id = Utilities.getUuid();
    sheet.appendRow([
      id, data.date, data.month, data.groceries, data.vegetables,
      data.fishEgg, data.chicken, data.houseRent, data.travel, data.others,
      data.dailyCash, data.broughtForward, data.totalExpenses, data.totalBalance, data.timestamp
    ]);
    return createJsonResponse({ status: 'success', id: id });
  }

  if (action === 'update') {
    const values = sheet.getDataRange().getValues();
    for (let i = 1; i < values.length; i++) {
      if (values[i][0] == data.id) {
        sheet.getRange(i + 1, 1, 1, 15).setValues([[
          data.id, data.date, data.month, data.groceries, data.vegetables,
          data.fishEgg, data.chicken, data.houseRent, data.travel, data.others,
          data.dailyCash, data.broughtForward, data.totalExpenses, data.totalBalance, data.timestamp
        ]]);
        break;
      }
    }
    return createJsonResponse({ status: 'success' });
  }

  if (action === 'delete') {
    const values = sheet.getDataRange().getValues();
    for (let i = 1; i < values.length; i++) {
      if (values[i][0] == data.id) {
        sheet.deleteRow(i + 1);
        break;
      }
    }
    return createJsonResponse({ status: 'success' });
  }

  // Handle Auth actions if needed
  if (action === 'register' || action === 'login') {
     // For this simple version, we'll return a mock success
     return createJsonResponse({ success: true, user: { id: "1", name: data.name || "User", email: data.email } });
  }

  return createJsonResponse({ status: 'error', message: 'Unknown action' });
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);

  if (!sheet) {
    setup();
    sheet = ss.getSheetByName(SHEET_NAME);
  }

  const values = sheet.getDataRange().getValues();
  if (values.length <= 1) {
    return createJsonResponse({ records: [] });
  }

  const headers = values[0];
  const records = [];

  const keyMap = {
    'ID': 'id',
    'Date': 'date',
    'Month': 'month',
    'Groceries': 'groceries',
    'Vegetables': 'vegetables',
    'FishEgg': 'fishEgg',
    'Chicken': 'chicken',
    'HouseRent': 'houseRent',
    'Travel': 'travel',
    'Others': 'others',
    'DailyCash': 'dailyCash',
    'BroughtForward': 'broughtForward',
    'TotalExpenses': 'totalExpenses',
    'TotalBalance': 'totalBalance',
    'Timestamp': 'timestamp'
  };

  for (let i = 1; i < values.length; i++) {
    const record = {};
    headers.forEach((header, index) => {
      const cleanHeader = header.toString().trim();
      const key = keyMap[cleanHeader] || cleanHeader.toLowerCase().replace(/\s+/g, '');
      let val = values[i][index];

      if ((cleanHeader === 'Date' || key === 'date') && val instanceof Date) {
        val = Utilities.formatDate(val, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
      }

      const numericFields = ['groceries', 'vegetables', 'fishEgg', 'chicken', 'houseRent', 'travel', 'others', 'dailyCash', 'broughtForward', 'totalExpenses', 'totalBalance'];
      if (numericFields.includes(key)) {
        val = val === "" ? 0 : Number(val);
      }

      record[key] = val;
    });
    records.push(record);
  }

  return createJsonResponse({ records });
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON)
    .addHeader("Access-Control-Allow-Origin", "*");
}

import { Transaction, User } from '../types';

const API_URL = 'https://script.google.com/macros/s/AKfycbw8Qo64ZJZuAptrshwpRmvCiv0Vw3Vv9ks4HR8XDU-kBNc_di3KDm0UR5ftdDTwGcVl/exec';

const getMockData = (): Transaction[] => {
  const data = localStorage.getItem('transactions_data_v2');
  return data ? JSON.parse(data) : [];
};

const saveMockData = (data: Transaction[]) => {
  localStorage.setItem('transactions_data_v2', JSON.stringify(data));
};

export const googleSheetsService = {
  async login(email: string, password: string): Promise<User | null> {
    try {
      const url = `${API_URL}${API_URL.includes('?') ? '&' : '?'}action=login&email=${encodeURIComponent(email)}&password=${encodeURIComponent(password)}`;
      const response = await fetch(url);
      if (!response.ok) return null;
      const data = await response.json();
      return data.success ? data.user : null;
    } catch (error) {
      console.error("Login failed", error);
      return null;
    }
  },

  async register(name: string, email: string, password: string): Promise<User | null> {
    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'register', name, email, password }),
      });
      const data = await response.json();
      return data.success ? data.user : null;
    } catch (error) {
      console.error("Registration failed", error);
      return null;
    }
  },

  async fetchTransactions(): Promise<Transaction[]> {
    try {
      const cacheBuster = `_t=${Date.now()}`;
      const url = `${API_URL}${API_URL.includes('?') ? '&' : '?'}action=read&${cacheBuster}`;

      const response = await fetch(url);
      if (!response.ok) throw new Error(`Fetch failed: ${response.status}`);

      const data = await response.json();

      if (data && Array.isArray(data.records)) {
        const cleanedRecords = data.records.map((r: any) => ({
          ...r,
          month: r.month ? String(r.month).trim() : 'Unknown',
          date: r.date ? String(r.date).trim() : '',
          totalExpenses: Number(r.totalExpenses) || 0,
          totalBalance: Number(r.totalBalance) || 0,
          dailyCash: Number(r.dailyCash) || 0
        }));

        saveMockData(cleanedRecords);
        return cleanedRecords;
      }
      return [];
    } catch (error) {
      console.error("Critical error fetching from Google Sheets:", error);
      return getMockData();
    }
  },

  async addTransaction(transaction: Transaction): Promise<boolean> {
    try {
      const payload = {
        action: 'create',
        ...transaction,
        timestamp: new Date().toISOString()
      };

      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify(payload),
      });

      // Since Google Apps Script redirects, a 200/302 is usually successful
      return response.ok;
    } catch (error) {
      console.error("Failed to add transaction", error);
      return false;
    }
  },

  async updateTransaction(id: string, transaction: Transaction): Promise<boolean> {
    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'update', id, ...transaction }),
      });
      return response.ok;
    } catch (error) {
      console.error("Failed to update transaction", error);
      return false;
    }
  },

  async deleteTransaction(id: string): Promise<boolean> {
    try {
      const response = await fetch(API_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'delete', id }),
      });
      return response.ok;
    } catch (error) {
      console.error("Failed to delete transaction", error);
      return false;
    }
  }
};

import React, { useState, useEffect } from 'react';
import { Transaction } from '../types';

interface TransactionFormProps {
  t: any;
  initialData?: Transaction | null;
  onSubmit: (data: Transaction) => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ t, initialData, onSubmit }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    groceries: '' as any,
    vegetables: '' as any,
    fishEgg: '' as any,
    chicken: '' as any,
    houseRent: '' as any,
    travel: '' as any,
    others: '' as any,
    dailyCash: '' as any,
    broughtForward: '' as any,
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        date: initialData.date,
        groceries: initialData.groceries || '',
        vegetables: initialData.vegetables || '',
        fishEgg: initialData.fishEgg || '',
        chicken: initialData.chicken || '',
        houseRent: initialData.houseRent || '',
        travel: initialData.travel || '',
        others: initialData.others || '',
        dailyCash: initialData.dailyCash || '',
        broughtForward: initialData.broughtForward || '',
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? (value === '' ? '' : parseFloat(value)) : value
    }));
  };

  const val = (v: any) => {
    const n = parseFloat(v);
    return isNaN(n) ? 0 : n;
  };

  const totalExpenses = 
    val(formData.groceries) + 
    val(formData.vegetables) + 
    val(formData.fishEgg) + 
    val(formData.chicken) + 
    val(formData.houseRent) +
    val(formData.travel) +
    val(formData.others);

  const totalBalance = val(formData.broughtForward) + val(formData.dailyCash) - totalExpenses;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // We use 'en-US' locale specifically for the month storage to ensure consistency
    // across different user locales.
    const dateObj = new Date(formData.date);
    const monthName = dateObj.toLocaleString('en-US', { month: 'long', year: 'numeric' });

    onSubmit({
      ...formData,
      groceries: val(formData.groceries),
      vegetables: val(formData.vegetables),
      fishEgg: val(formData.fishEgg),
      chicken: val(formData.chicken),
      houseRent: val(formData.houseRent),
      travel: val(formData.travel),
      others: val(formData.others),
      dailyCash: val(formData.dailyCash),
      broughtForward: val(formData.broughtForward),
      month: monthName,
      totalExpenses,
      totalBalance,
      timestamp: new Date().toISOString()
    });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.date}</label>
          <input
            type="date"
            name="date"
            required
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.date}
            onChange={handleChange}
          />
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-1">{t.broughtForward}</label>
          <input
            type="number"
            name="broughtForward"
            placeholder="0"
            className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={formData.broughtForward}
            onChange={handleChange}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {[
          { name: 'dailyCash', label: t.dailyCash, highlight: true },
          { name: 'groceries', label: t.groceries },
          { name: 'vegetables', label: t.vegetables },
          { name: 'fishEgg', label: t.fishEgg },
          { name: 'chicken', label: t.chicken },
          { name: 'houseRent', label: t.houseRent },
          { name: 'travel', label: t.travel },
          { name: 'others', label: t.others },
        ].map(field => (
          <div key={field.name}>
            <label className={`block text-sm font-semibold mb-1 ${field.highlight ? 'text-indigo-700' : 'text-slate-700'}`}>{field.label}</label>
            <input
              type="number"
              name={field.name}
              placeholder="0"
              className={`w-full px-4 py-2.5 rounded-xl border transition-all focus:ring-2 focus:ring-indigo-500 outline-none ${field.highlight ? 'border-indigo-200 bg-indigo-50 font-bold' : 'border-slate-200'}`}
              value={(formData as any)[field.name]}
              onChange={handleChange}
            />
          </div>
        ))}
      </div>

      <div className="p-6 bg-slate-50 rounded-2xl flex flex-wrap gap-8 items-center justify-center border border-slate-100">
        <div className="text-center">
          <p className="text-xs text-slate-400 uppercase tracking-wider font-bold">{t.totalExpenses}</p>
          <p className="text-2xl font-black text-rose-600">LKR {totalExpenses.toLocaleString()}</p>
        </div>
        <div className="text-center">
          <p className="text-xs text-slate-400 uppercase tracking-wider font-bold">{t.totalBalance}</p>
          <p className="text-2xl font-black text-emerald-600">LKR {totalBalance.toLocaleString()}</p>
        </div>
      </div>

      <button
        type="submit"
        className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-[0.99] transition-all"
      >
        {t.save}
      </button>
    </form>
  );
};

