export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Transaction, MonthlySummary } from '../types';
import TransactionForm from './TransactionForm';
import StatsOverview from './StatsOverview';
import MonthlyCharts from './MonthlyCharts';
import HistoryTable from './HistoryTable';
import { Plus, X, Calendar, BarChart3, ClipboardList, ArrowRight, RefreshCw } from 'lucide-react';

interface DashboardProps {
  activeTab: 'dashboard' | 'analytics' | 'history';
  setActiveTab?: (tab: 'dashboard' | 'analytics' | 'history') => void;
  t: any;
  transactions: Transaction[];
  onAdd: (data: Transaction) => void;
  onUpdate: (id: string, data: Transaction) => void;
  onDelete: (id: string) => void;
  onRefresh: () => void;
  isLoading: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  activeTab, 
  setActiveTab,
  t, 
  transactions, 
  onAdd, 
  onUpdate,
  onDelete,
  onRefresh,
  isLoading 
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const currentMonthName = useMemo(() => {
    return new Date().toLocaleString('en-US', { month: 'long', year: 'numeric' });
  }, []);

  const availableMonths = useMemo(() => {
    const monthsSet = new Set<string>();
    transactions.forEach(tx => {
      if (tx.month) monthsSet.add(tx.month.trim());
    });
    monthsSet.add(currentMonthName);
    return Array.from(monthsSet).sort((a, b) => {
      const dateA = new Date(a);
      const dateB = new Date(b);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions, currentMonthName]);

  const [selectedMonth, setSelectedMonth] = useState<string>(availableMonths[0] || currentMonthName);

  useEffect(() => {
    const trimmedMonthsWithData = transactions.map(tx => tx.month?.trim());
    if (transactions.length > 0 && !trimmedMonthsWithData.includes(selectedMonth)) {
      setSelectedMonth(trimmedMonthsWithData[0] || currentMonthName);
    }
  }, [transactions]);

  const monthlySummary: MonthlySummary[] = useMemo(() => {
    const summaryMap: Record<string, MonthlySummary> = {};

    transactions.forEach((tx) => {
      const monthKey = tx.month?.trim() || 'Unknown';
      if (!summaryMap[monthKey]) {
        summaryMap[monthKey] = {
          month: monthKey,
          totalGroceries: 0,
          totalVegetables: 0,
          totalFishEgg: 0,
          totalChicken: 0,
          totalHouseRent: 0,
          totalTravel: 0,
          totalOthers: 0,
          totalExpenses: 0,
          totalDailyCash: 0,
          broughtForward: Number(tx.broughtForward) || 0,
          totalBalance: 0
        };
      }
      summaryMap[monthKey].totalGroceries += (Number(tx.groceries) || 0);
      summaryMap[monthKey].totalVegetables += (Number(tx.vegetables) || 0);
      summaryMap[monthKey].totalFishEgg += (Number(tx.fishEgg) || 0);
      summaryMap[monthKey].totalChicken += (Number(tx.chicken) || 0);
      summaryMap[monthKey].totalHouseRent += (Number(tx.houseRent) || 0);
      summaryMap[monthKey].totalTravel += (Number(tx.travel) || 0);
      summaryMap[monthKey].totalOthers += (Number(tx.others) || 0);
      summaryMap[monthKey].totalExpenses += (Number(tx.totalExpenses) || 0);
      summaryMap[monthKey].totalDailyCash += (Number(tx.dailyCash) || 0);
      summaryMap[monthKey].totalBalance = (Number(tx.totalBalance) || 0); 
    });

    return Object.values(summaryMap).sort((a, b) => {
      const dateA = new Date(a.month);
      const dateB = new Date(b.month);
      return dateB.getTime() - dateA.getTime();
    });
  }, [transactions]);

  const filteredStats = useMemo(() => {
    const monthTx = transactions.filter(tx => tx.month?.trim() === selectedMonth);
    const totalSpent = monthTx.reduce((sum, tx) => sum + (Number(tx.totalExpenses) || 0), 0);
    const totalReceived = monthTx.reduce((sum, tx) => sum + (Number(tx.dailyCash) || 0), 0);
    const lastBalance = monthTx.length > 0 ? (Number(monthTx[monthTx.length - 1].totalBalance) || 0) : 0;

    return { totalSpent, totalReceived, lastBalance };
  }, [transactions, selectedMonth]);

  const handleEdit = (tx: Transaction) => {
    setEditingTransaction(tx);
    setShowAddForm(true);
  };

  const handleCloseForm = () => {
    setShowAddForm(false);
    setEditingTransaction(null);
  };

  const currentMonthTransactions = useMemo(() => {
    return transactions.filter(tx => tx.month?.trim() === selectedMonth).sort((a, b) => a.date.localeCompare(b.date));
  }, [transactions, selectedMonth]);

  const recentTransactions = useMemo(() => {
    return transactions.slice().reverse().slice(0, 10);
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 rounded-3xl border border-slate-100 shadow-sm">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 bg-indigo-50 rounded-xl">
            <Calendar className="w-5 h-5 text-indigo-600" />
          </div>
          <div className="flex-grow">
            <h2 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none mb-1">{t.selectMonth}</h2>
            <select 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent font-bold text-lg text-slate-800 outline-none cursor-pointer hover:text-indigo-600 transition-colors"
            >
              {availableMonths.map(m => (
                <option key={m} value={m}>{m}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <button 
            onClick={onRefresh}
            disabled={isLoading}
            className={`flex items-center gap-2 px-6 py-3 bg-slate-50 text-slate-600 rounded-2xl font-bold hover:bg-slate-100 hover:text-indigo-600 transition-all border border-slate-100 ${isLoading ? 'opacity-70 cursor-not-allowed' : 'active:scale-95'}`}
            title={t.refreshData}
          >
            <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            <span className="hidden sm:inline">{t.refreshData}</span>
          </button>
          <button 
            onClick={() => setShowAddForm(true)}
            className="flex-grow sm:flex-grow-0 bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all"
          >
            <Plus className="w-5 h-5" />
            {t.addRecord}
          </button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <>
          <StatsOverview t={t} stats={filteredStats} />

          <div className="mt-8 bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <ClipboardList className="w-6 h-6 text-indigo-600" />
                <h2 className="text-xl font-bold text-slate-800">{t.recentTransactions}</h2>
              </div>
              <button 
                onClick={() => setActiveTab?.('history')}
                className="flex items-center gap-1 text-sm font-bold text-indigo-600 hover:text-indigo-700 transition-colors"
              >
                {t.viewAll}
                <ArrowRight className="w-4 h-4" />
              </button>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left min-w-[800px]">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-[10px] uppercase font-black tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4">{t.date}</th>
                    <th className="px-6 py-4">{t.month}</th>
                    <th className="px-6 py-4">{t.dailyCash}</th>
                    <th className="px-6 py-4">{t.totalExpenses}</th>
                    <th className="px-6 py-4 bg-indigo-50/30 text-indigo-700">{t.totalBalance}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {recentTransactions.map((tx) => (
                    <tr key={tx.id || tx.timestamp} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4 text-sm font-semibold text-slate-700">{tx.date.split('-').reverse().join('/')}</td>
                      <td className="px-6 py-4 text-xs font-medium text-slate-400">{tx.month}</td>
                      <td className="px-6 py-4 text-sm font-bold text-emerald-600">LKR {Number(tx.dailyCash)?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-bold text-rose-500">LKR {Number(tx.totalExpenses)?.toLocaleString()}</td>
                      <td className="px-6 py-4 text-sm font-black text-indigo-600 bg-indigo-50/20">LKR {Number(tx.totalBalance)?.toLocaleString()}</td>
                    </tr>
                  ))}
                  {recentTransactions.length === 0 && (
                    <tr>
                      <td colSpan={5} className="px-6 py-12 text-center text-slate-400 font-medium italic">{t.noData}</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>

          <div className="mt-8">
            <h2 className="text-xl font-bold text-slate-800 mb-4">{t.summary}</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {monthlySummary.map((sum) => (
                  <div 
                    key={sum.month} 
                    onClick={() => setSelectedMonth(sum.month)}
                    className={`bg-white p-6 rounded-3xl shadow-sm border transition-all cursor-pointer ${selectedMonth === sum.month ? 'border-indigo-500 ring-2 ring-indigo-50' : 'border-slate-100 hover:shadow-md'}`}
                  >
                    <div className="flex justify-between items-center mb-4">
                       <h3 className="font-bold text-lg text-indigo-600">{sum.month}</h3>
                       {sum.month === currentMonthName && (
                         <span className="bg-emerald-50 text-emerald-700 text-[10px] font-black px-2 py-0.5 rounded-full uppercase">Current</span>
                       )}
                    </div>
                    <div className="space-y-2">
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.totalExpenses}</span>
                         <span className="font-semibold text-rose-500">LKR {sum.totalExpenses.toLocaleString()}</span>
                       </div>
                       <div className="flex justify-between text-sm">
                         <span className="text-slate-500">{t.dailyCash}</span>
                         <span className="font-semibold text-emerald-600">LKR {sum.totalDailyCash.toLocaleString()}</span>
                       </div>
                       <div className="pt-2 border-t border-slate-50 flex justify-between">
                         <span className="font-bold text-slate-700">{t.totalBalance}</span>
                         <span className="font-bold text-slate-900">LKR {sum.totalBalance.toLocaleString()}</span>
                       </div>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        </>
      )}

      {activeTab === 'analytics' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div>
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-100 rounded-xl">
                  <BarChart3 className="w-6 h-6 text-indigo-700" />
                </div>
                <h2 className="text-2xl font-black text-slate-800">{t.charts} - {selectedMonth}</h2>
              </div>
              <button 
                onClick={onRefresh}
                disabled={isLoading}
                className={`flex items-center gap-2 px-5 py-2.5 bg-white text-slate-600 rounded-2xl font-bold hover:text-indigo-600 transition-all border border-slate-100 shadow-sm ${isLoading ? 'opacity-70 cursor-not-allowed' : 'active:scale-95'}`}
              >
                <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
                <span>{t.refreshData}</span>
              </button>
            </div>
            <MonthlyCharts t={t} transactions={currentMonthTransactions} />
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="p-6 border-b border-slate-100 flex items-center justify-between">
            <h2 className="text-xl font-bold text-slate-800">{t.history} ({selectedMonth})</h2>
            <button 
              onClick={onRefresh}
              disabled={isLoading}
              className={`flex items-center gap-2 px-4 py-2 bg-slate-50 text-slate-500 rounded-xl text-xs font-bold hover:text-indigo-600 transition-all ${isLoading ? 'opacity-70 cursor-not-allowed' : 'active:scale-95'}`}
            >
              <RefreshCw className={`w-3.5 h-3.5 ${isLoading ? 'animate-spin' : ''}`} />
              <span>{t.refreshData}</span>
            </button>
          </div>
          <HistoryTable 
            t={t} 
            transactions={transactions.filter(tx => tx.month?.trim() === selectedMonth)} 
            allTransactions={transactions}
            onEdit={handleEdit} 
            onDelete={onDelete} 
            isLoading={isLoading} 
          />
        </div>
      )}

      {showAddForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col scale-in-center">
